{
  "name": "FLUX Assessment",
  "description": "A comprehensive psychological assessment tool for athletes featuring IPPS-24, MTS, C&T, and PESD questionnaires with real-time visualization."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface AthleteProfile {
  name: string;
  discipline: string;
  yearsOfPractice: number;
}

export type QuestionnaireType = 'IPPS' | 'MTS' | 'CT' | 'PESD';

export interface QuestionnaireData {
  ipps: number[];
  mts: number[];
  ct: number[];
  pesd: number[];
}

export interface PesdItem {
  left: string;
  right: string;
}

export interface AssessmentRecord extends AthleteProfile, QuestionnaireData {
  id: string;
  date: string;
}

export interface TabProps {
  data: number[];
  onChange: (index: number, value: number) => void;
}

import React from 'react';
import { IPPS_ITEMS, MTS_ITEMS, CT_ITEMS } from '../constants';
import { TabProps } from '../types';

interface SliderItemProps {
    label: string;
    value: number;
    min: number;
    max: number;
    onChange: (val: number) => void;
}

const SliderItem: React.FC<SliderItemProps> = ({ label, value, min, max, onChange }) => {
    return (
        <div className="mb-6 p-4 bg-white rounded-lg shadow-sm border border-gray-100 hover:border-red-100 transition-colors">
            <label className="block text-sm font-medium text-gray-800 mb-3">{label}</label>
            <div className="flex items-center gap-4">
                <span className="text-sm font-bold text-gray-500 w-4">{min}</span>
                <input
                    type="range"
                    min={min}
                    max={max}
                    value={value}
                    onChange={(e) => onChange(parseInt(e.target.value))}
                    className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-red-600"
                />
                <span className="text-sm font-bold text-gray-500 w-4">{max}</span>
                <span className="ml-2 w-8 text-center text-lg font-bold text-red-600">{value}</span>
            </div>
        </div>
    );
};

export const IppsTab: React.FC<TabProps> = ({ data, onChange }) => {
    return (
        <div className="space-y-4">
            <div className="mb-4">
                <h3 className="text-xl font-bold text-gray-900">IPPS-24</h3>
                <p className="text-sm text-gray-500">Scala: 1 (Mai) - 6 (Sempre)</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {IPPS_ITEMS.map((item, index) => (
                    <SliderItem
                        key={index}
                        label={item}
                        value={data[index]}
                        min={1}
                        max={6}
                        onChange={(val) => onChange(index, val)}
                    />
                ))}
            </div>
        </div>
    );
};

export const MtsTab: React.FC<TabProps> = ({ data, onChange }) => {
    return (
        <div className="space-y-4">
            <div className="mb-4">
                <h3 className="text-xl font-bold text-gray-900">Mental Toughness Scale</h3>
                <p className="text-sm text-gray-500">Scala: 1 (Fortemente in disaccordo) - 5 (Fortemente d'accordo)</p>
            </div>
            <div className="space-y-2">
                {MTS_ITEMS.map((item, index) => (
                    <SliderItem
                        key={index}
                        label={item}
                        value={data[index]}
                        min={1}
                        max={5}
                        onChange={(val) => onChange(index, val)}
                    />
                ))}
            </div>
        </div>
    );
};

export const CtTab: React.FC<TabProps> = ({ data, onChange }) => {
    return (
        <div className="space-y-4">
            <div className="mb-4">
                <h3 className="text-xl font-bold text-gray-900">Challenge & Threat</h3>
                <p className="text-sm text-gray-500">Scala: 1 (Per nulla vera) - 7 (Completamente vera)</p>
            </div>
            <div className="space-y-2">
                {CT_ITEMS.map((item, index) => (
                    <SliderItem
                        key={index}
                        label={item}
                        value={data[index]}
                        min={1}
                        max={7}
                        onChange={(val) => onChange(index, val)}
                    />
                ))}
            </div>
        </div>
    );
};

import React from 'react';
import { PESD_ITEMS } from '../constants';
import { TabProps } from '../types';

export const PesdTab: React.FC<TabProps> = ({ data, onChange }) => {
    return (
        <div className="space-y-6">
            <div className="mb-6">
                <h3 className="text-xl font-bold text-gray-900">Esperienze Psicobiosociali (PESD)</h3>
                <p className="text-sm text-gray-500">
                    Sposta il cursore verso il descrittore che senti tuo. (0 = Neutro)
                </p>
            </div>

            <div className="grid grid-cols-1 gap-4">
                {PESD_ITEMS.map((item, index) => (
                    <div key={index} className="bg-white p-4 rounded-lg shadow-sm border border-gray-100">
                        <div className="flex justify-between text-sm font-semibold mb-2">
                            <span className="text-red-500 w-1/3 text-left">{item.left}</span>
                            <span className="text-gray-400 w-1/3 text-center text-xs uppercase tracking-wider">Neutro</span>
                            <span className="text-green-600 w-1/3 text-right">{item.right}</span>
                        </div>

                        <div className="relative pt-1">
                            <input
                                type="range"
                                min={-4}
                                max={4}
                                step={1}
