                                <span>+2</span>
                                <span>+3</span>
                                <span>+4</span>
                            </div>
                        </div>

                        <div className="text-center mt-2">
                            <span className={`inline-block px-3 py-1 rounded-full text-xs font-bold ${
                                data[index] < 0 ? 'bg-red-100 text-red-700' : 
                                data[index] > 0 ? 'bg-green-100 text-green-700' : 
                                'bg-gray-100 text-gray-600'
