import React, { useMemo, useState, useEffect } from 'react';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer } from 'recharts';
import { Download, Save, History, Trash2, AlertCircle } from 'lucide-react';
import { AthleteProfile, QuestionnaireData, AssessmentRecord } from '../types';

interface ResultsTabProps {
    profile: AthleteProfile;
    data: QuestionnaireData;
    onSave: () => void;
    history: AssessmentRecord[];
    onClearHistory: () => void;
}

export const ResultsTab: React.FC<ResultsTabProps> = ({ profile, data, onSave, history, onClearHistory }) => {
    const [canSave, setCanSave] = useState(false);

    useEffect(() => {
        setCanSave(profile.name.trim().length > 0);
    }, [profile.name]);

    const stats = useMemo(() => {
        const calcMean = (arr: number[]) => arr.reduce((a, b) => a + b, 0) / arr.length;

        const meanIpps = calcMean(data.ipps);
        const normIpps = ((meanIpps - 1) / 5) * 100;

        const meanMts = calcMean(data.mts);
        const normMts = ((meanMts - 1) / 4) * 100;

        const meanCt = calcMean(data.ct);
        const normCt = ((meanCt - 1) / 6) * 100;

        const meanPesd = calcMean(data.pesd);
        // PESD range is -4 to 4 (total 8)
        const normPesd = ((meanPesd + 4) / 8) * 100;

        return {
            raw: { meanIpps, meanMts, meanCt, meanPesd },
            norm: { normIpps, normMts, normCt, normPesd },
            chartData: [
                { subject: 'IPPS-24', A: normIpps, fullMark: 100 },
                { subject: 'MTS', A: normMts, fullMark: 100 },
                { subject: 'C&T', A: normCt, fullMark: 100 },
                { subject: 'PESD', A: normPesd, fullMark: 100 },
            ]
        };
    }, [data]);

    const downloadCsv = () => {
        if (history.length === 0) return;

        // Build header
        const keys = Object.keys(history[0]);
        // We need to flatten the arrays for CSV
        let csvContent = "data:text/csv;charset=utf-8,";

        // Custom Header
        csvContent += "ID,Date,Name,Discipline,Years,IPPS_Mean,MTS_Mean,CT_Mean,PESD_Mean\n";

        history.forEach(row => {
            const ippsMean = (row.ipps.reduce((a,b)=>a+b,0) / row.ipps.length).toFixed(2);
            const mtsMean = (row.mts.reduce((a,b)=>a+b,0) / row.mts.length).toFixed(2);
            const ctMean = (row.ct.reduce((a,b)=>a+b,0) / row.ct.length).toFixed(2);
            const pesdMean = (row.pesd.reduce((a,b)=>a+b,0) / row.pesd.length).toFixed(2);

            const line = `${row.id},${row.date},${row.name},${row.discipline},${row.yearsOfPractice},${ippsMean},${mtsMean},${ctMean},${pesdMean}`;
            csvContent += line + "\n";
        });

        const encodedUri = encodeURI(csvContent);
        const link = document.createElement("a");
        link.setAttribute("href", encodedUri);
        link.setAttribute("download", `flux_assessment_${new Date().toISOString().split('T')[0]}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div className="space-y-8">
            <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100">
                <div className="flex flex-col md:flex-row justify-between items-center mb-6">
                    <h3 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                        <div className="w-2 h-8 bg-red-600 rounded-full"></div>
                        Analisi Profilo: {profile.name || "Anonimo"}
                    </h3>

                    <div className="flex gap-2 mt-4 md:mt-0">
                        <button
                            onClick={onSave}
                            disabled={!canSave}
                            className={`flex items-center gap-2 px-6 py-2 rounded-lg font-medium transition-all ${
                                canSave 
                                ? 'bg-red-600 text-white hover:bg-red-700 shadow-lg shadow-red-200' 
                                : 'bg-gray-200 text-gray-400 cursor-not-allowed'
                            }`}
                        >
                            <Save size={18} />
                            Salva Risultati
                        </button>
                    </div>
                </div>

                {!canSave && (
                    <div className="mb-6 p-4 bg-yellow-50 text-yellow-800 rounded-lg flex items-center gap-2">
                        <AlertCircle size={20} />
                        <span>Inserisci il nome dell'atleta nella barra laterale per salvare i dati.</span>
                    </div>
                )}

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    {/* Chart */}
                    <div className="h-[400px] w-full bg-gray-50 rounded-xl p-4 flex items-center justify-center">
                        <ResponsiveContainer width="100%" height="100%">
                            <RadarChart cx="50%" cy="50%" outerRadius="80%" data={stats.chartData}>
                                <PolarGrid stroke="#e5e7eb" />
                                <PolarAngleAxis dataKey="subject" tick={{ fill: '#4b5563', fontSize: 14, fontWeight: 'bold' }} />
                                <PolarRadiusAxis angle={30} domain={[0, 100]} tick={{ fill: '#9ca3af' }} />
                                <Radar
                                    name={profile.name}
                                    dataKey="A"
                                    stroke="#dc2626"
                                    strokeWidth={3}
                                    fill="#ef4444"
                                    fillOpacity={0.4}
                                />
                            </RadarChart>
                        </ResponsiveContainer>
                    </div>

                    {/* Metrics */}
                    <div className="grid grid-cols-2 gap-4 content-center">
                        <div className="bg-blue-50 p-6 rounded-xl border border-blue-100">
                            <p className="text-sm text-blue-600 font-semibold uppercase tracking-wider">IPPS-24</p>
                            <p className="text-3xl font-bold text-blue-900">{stats.raw.meanIpps.toFixed(2)}</p>
                            <p className="text-xs text-blue-400 mt-1">Prestazione</p>
                        </div>
                        <div className="bg-purple-50 p-6 rounded-xl border border-purple-100">
                            <p className="text-sm text-purple-600 font-semibold uppercase tracking-wider">MTS</p>
                            <p className="text-3xl font-bold text-purple-900">{stats.raw.meanMts.toFixed(2)}</p>
                            <p className="text-xs text-purple-400 mt-1">Mental Toughness</p>
                        </div>
                        <div className="bg-orange-50 p-6 rounded-xl border border-orange-100">
                            <p className="text-sm text-orange-600 font-semibold uppercase tracking-wider">C&T</p>
                            <p className="text-3xl font-bold text-orange-900">{stats.raw.meanCt.toFixed(2)}</p>
                            <p className="text-xs text-orange-400 mt-1">Challenge & Threat</p>
                        </div>
                        <div className="bg-green-50 p-6 rounded-xl border border-green-100">
                            <p className="text-sm text-green-600 font-semibold uppercase tracking-wider">PESD</p>
                            <p className="text-3xl font-bold text-green-900">{stats.raw.meanPesd.toFixed(2)}</p>
                            <p className="text-xs text-green-400 mt-1">Stato Funzionale</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* History Table */}
            <div className="bg-white rounded-xl shadow-md border border-gray-100 overflow-hidden">
                <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                    <h4 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                        <History size={20} className="text-gray-500" />
                        Database Locale
                    </h4>
                    <div className="flex gap-2">
                         <button 
                            onClick={onClearHistory}
                            className="flex items-center gap-2 px-3 py-1.5 text-sm text-red-600 hover:bg-red-50 rounded-md transition-colors"
                        >
                            <Trash2 size={16} />
                            Reset DB
                        </button>
                        <button 
                            onClick={downloadCsv}
                            className="flex items-center gap-2 px-4 py-2 bg-gray-800 text-white rounded-lg hover:bg-gray-900 transition-colors text-sm"
                        >
                            <Download size={16} />
                            Download CSV
                        </button>
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left text-gray-500">
                        <thead className="text-xs text-gray-700 uppercase bg-gray-100">
                            <tr>
                                <th scope="col" className="px-6 py-3">Data</th>
                                <th scope="col" className="px-6 py-3">Atleta</th>
                                <th scope="col" className="px-6 py-3">Disciplina</th>
                                <th scope="col" className="px-6 py-3">IPPS</th>
                                <th scope="col" className="px-6 py-3">MTS</th>
                                <th scope="col" className="px-6 py-3">C&T</th>
                                <th scope="col" className="px-6 py-3">PESD</th>
                            </tr>
                        </thead>
                        <tbody>
                            {history.length > 0 ? (
                                history.map((record) => {
                                    const mIpps = (record.ipps.reduce((a,b)=>a+b,0)/record.ipps.length).toFixed(2);
                                    const mMts = (record.mts.reduce((a,b)=>a+b,0)/record.mts.length).toFixed(2);
                                    const mCt = (record.ct.reduce((a,b)=>a+b,0)/record.ct.length).toFixed(2);
                                    const mPesd = (record.pesd.reduce((a,b)=>a+b,0)/record.pesd.length).toFixed(2);

                                    return (
                                        <tr key={record.id} className="bg-white border-b hover:bg-gray-50">
                                            <td className="px-6 py-4">{record.date}</td>
                                            <td className="px-6 py-4 font-medium text-gray-900">{record.name}</td>
                                            <td className="px-6 py-4">{record.discipline}</td>
                                            <td className="px-6 py-4">{mIpps}</td>
                                            <td className="px-6 py-4">{mMts}</td>
                                            <td className="px-6 py-4">{mCt}</td>
                                            <td className="px-6 py-4">{mPesd}</td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={7} className="px-6 py-8 text-center text-gray-400">
                                        Nessun dato registrato.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Target, Brain, Swords, Activity, PieChart, Menu, X } from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { IppsTab, MtsTab, CtTab } from './components/Questionnaires';
import { PesdTab } from './components/PesdTab';
import { ResultsTab } from './components/ResultsTab';
import { IPPS_ITEMS, MTS_ITEMS, CT_ITEMS, PESD_ITEMS } from './constants';
import { AthleteProfile, AssessmentRecord } from './types';

function App() {
  const [profile, setProfile] = useState<AthleteProfile>({
    name: '',
    discipline: 'Carabina',
    yearsOfPractice: 0
  });

  // State for all questionnaires
  // Initialize with middle values (default logic from python script)
  const [ippsData, setIppsData] = useState<number[]>(new Array(IPPS_ITEMS.length).fill(3));
  const [mtsData, setMtsData] = useState<number[]>(new Array(MTS_ITEMS.length).fill(3));
  const [ctData, setCtData] = useState<number[]>(new Array(CT_ITEMS.length).fill(4));
  const [pesdData, setPesdData] = useState<number[]>(new Array(PESD_ITEMS.length).fill(0));

  const [activeTab, setActiveTab] = useState(0);
  const [history, setHistory] = useState<AssessmentRecord[]>([]);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Load history from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('flux_db');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  const handleProfileChange = (field: keyof AthleteProfile, value: string | number) => {
    setProfile(prev => ({ ...prev, [field]: value }));
  };

  const updateQuestionnaire = (setter: React.Dispatch<React.SetStateAction<number[]>>, index: number, val: number) => {
    setter(prev => {
      const copy = [...prev];
      copy[index] = val;
      return copy;
    });
  };

  const saveRecord = () => {
    if (!profile.name) return;

    const newRecord: AssessmentRecord = {
      id: Date.now().toString(),
      date: new Date().toISOString().split('T')[0],
      ...profile,
      ipps: ippsData,
      mts: mtsData,
      ct: ctData,
      pesd: pesdData
    };

    const newHistory = [...history, newRecord];
    setHistory(newHistory);
    localStorage.setItem('flux_db', JSON.stringify(newHistory));
    alert("Dati salvati correttamente nel Database!");
  };

  const clearHistory = () => {
    if (confirm("Sei sicuro di voler cancellare tutto lo storico?")) {
        setHistory([]);
        localStorage.removeItem('flux_db');
    }
  };

  const tabs = [
    { id: 0, label: 'IPPS-24', icon: Target, component: <IppsTab data={ippsData} onChange={(i, v) => updateQuestionnaire(setIppsData, i, v)} /> },
    { id: 1, label: 'MTS', icon: Brain, component: <MtsTab data={mtsData} onChange={(i, v) => updateQuestionnaire(setMtsData, i, v)} /> },
    { id: 2, label: 'C&T', icon: Swords, component: <CtTab data={ctData} onChange={(i, v) => updateQuestionnaire(setCtData, i, v)} /> },
    { id: 3, label: 'PESD', icon: Activity, component: <PesdTab data={pesdData} onChange={(i, v) => updateQuestionnaire(setPesdData, i, v)} /> },
    { id: 4, label: 'Risultati', icon: PieChart, component: <ResultsTab profile={profile} data={{ ipps: ippsData, mts: mtsData, ct: ctData, pesd: pesdData }} onSave={saveRecord} history={history} onClearHistory={clearHistory} /> }
  ];

  return (
    <div className="flex h-screen overflow-hidden bg-gray-50 font-sans">
      {/* Mobile Sidebar Overlay */}
      {sidebarOpen && (
        <div 
            className="fixed inset-0 bg-black/50 z-40 md:hidden"
            onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* Sidebar Wrapper */}
      <div className={`
        fixed md:relative z-50 h-full transition-transform duration-300 ease-in-out
        ${sidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
          <Sidebar profile={profile} onChange={handleProfileChange} />
          {/* Close button for mobile */}
          <button 
            className="absolute top-4 right-4 md:hidden text-gray-500"
            onClick={() => setSidebarOpen(false)}
          >
            <X />
          </button>
      </div>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden w-full">

        {/* Header (Mobile only toggle) */}
        <div className="md:hidden bg-white border-b border-gray-200 p-4 flex items-center justify-between">
            <div className="flex items-center gap-2 font-black text-gray-900">
                <span className="bg-yellow-400 p-1 rounded text-white"><Target size={16} fill="currentColor" /></span>
                FLUX
            </div>
            <button onClick={() => setSidebarOpen(true)} className="text-gray-600">
                <Menu />
            </button>
        </div>

        {/* Tabs Header */}
        <div className="bg-white border-b border-gray-200 px-6 py-2 overflow-x-auto scrollbar-hide flex-shrink-0">
          <div className="flex space-x-8 min-w-max">
            {tabs.map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`
                  flex items-center gap-2 py-4 px-1 border-b-2 transition-colors font-medium text-sm
                  ${activeTab === tab.id 
                    ? 'border-red-600 text-red-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}
                `}
              >
                <tab.icon size={18} />
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8">
            <div className="max-w-5xl mx-auto pb-20">
                <div className="animate-fade-in-up">
                    {tabs[activeTab].component}
                </div>
            </div>
        </div>
      </main>
    </div>
  );
}

export default App;

import { PesdItem } from './types';

export const DISCIPLINES = ["Carabina", "Pistola", "Tiro a Volo", "Altro"];

export const IPPS_ITEMS = [
    "1. Prima della gara ho un senso di panico",
    "2. Mi considero una persona determinata quando gareggio",
    "3. Quando gareggio sono distratto dalla presenza di pubblico o di altri disturbi esterni",
    "4. Quando mi sento troppo teso sono in grado di rilassarmi rapidamente e di ritrovare la calma",
    "5. Quando gareggio sono preoccupato di commettere errori o di fallire",
    "6. In gara sono motivato al punto giusto per rendere al massimo",
    "7. Durante la gara i miei pensieri sono altrove",
    "8. Quando sono troppo teso per ciò che devo fare riesco a rilassarmi",
    "9. Mi preoccupo molto di commettere errori",
