interface SliderItemProps {
    label: string;
    value: number;
    min: number;
    max: number;
    labels: string[];
    onChange: (val: number) => void;
}

const SliderItem: React.FC<SliderItemProps> = ({ label, value, min, max, labels, onChange }) => {
    // Calculate percentage for gradient background or positioning
    const percentage = ((value - min) / (max - min)) * 100;

    return (
        <div className="mb-8 p-6 bg-white rounded-xl shadow-sm border border-gray-100 hover:border-red-100 transition-colors">
            <h4 className="text-md font-semibold text-gray-800 mb-6">{label}</h4>

            <div className="relative mb-6">
                <input
                    type="range"
                    min={min}
                    max={max}
                    value={value}
                    onChange={(e) => onChange(parseInt(e.target.value))}
                    className="w-full h-3 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-red-600 z-10 relative"
                />
                {/* Ticks */}
                <div className="absolute top-4 left-0 w-full flex justify-between px-1">
                    {labels.map((l, i) => (
                        <div key={i} className="flex flex-col items-center w-8">
                            <div className="h-2 w-0.5 bg-gray-300 mb-1"></div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="flex justify-between items-start text-xs text-gray-500 font-medium">
                {labels.map((l, i) => (
                    <div 
                        key={i} 
                        className={`text-center w-16 transition-colors ${
                            value === min + i ? 'text-red-600 font-bold scale-110' : ''
                        }`}
                        onClick={() => onChange(min + i)}
                        style={{ cursor: 'pointer' }}
                    >
                        {l}
                    </div>
                ))}
            </div>

            <div className="mt-4 text-center">
                 <span className="inline-block px-3 py-1 bg-gray-100 text-gray-700 rounded-md font-bold text-sm">
                    Punteggio: {value}
                 </span>
            </div>
        </div>
    );
};

