interface ResultsTabProps {
    profile: AthleteProfile;
    data: QuestionnaireData;
    onSave: () => void;
    history: AssessmentRecord[];
    onClearHistory: () => void;
}

// Helper to calculate mean
const mean = (indices: number[], values: number[]) => {
    if (indices.length === 0) return 0;
    const sum = indices.reduce((acc, idx) => acc + values[idx], 0);
    return sum / indices.length;
};

// Colors
const COLORS = {
    positive: '#22c55e', // Green 500
    negative: '#ef4444', // Red 500
    neutral: '#9ca3af'   // Gray 400
};

export const ResultsTab: React.FC<ResultsTabProps> = ({ profile, data, onSave, history, onClearHistory }) => {
    const [canSave, setCanSave] = useState(false);

    useEffect(() => {
        setCanSave(profile.name.trim().length > 0);
    }, [profile.name]);

    const results = useMemo(() => {
        // --- IPPS SCORING ---
        // 4 Subscales, range 1-6
        const ippsScores = [
            { name: 'Fiducia', val: mean(IPPS_SUBSCALES.confidence, data.ipps), type: 'pos', max: 6 },
            { name: 'Controllo (+)', val: mean(IPPS_SUBSCALES.control, data.ipps), type: 'pos', max: 6 },
            { name: 'Ansia', val: mean(IPPS_SUBSCALES.anxiety, data.ipps), type: 'neg', max: 6 },
            { name: 'Distrazione', val: mean(IPPS_SUBSCALES.distraction, data.ipps), type: 'neg', max: 6 },
        ];

        // --- MTS SCORING ---
        // Single scale, range 1-5
        const mtsScore = data.mts.reduce((a, b) => a + b, 0) / data.mts.length;
        const mtsData = [
            { name: 'Mental Toughness', val: mtsScore, type: 'pos', max: 5 }
        ];

        // --- C&T SCORING ---
        // 2 Subscales, range 1-7
        const ctScores = [
            { name: 'Challenge (Sfida)', val: mean(CT_SUBSCALES.challenge, data.ct), type: 'pos', max: 7 },
            { name: 'Threat (Minaccia)', val: mean(CT_SUBSCALES.threat, data.ct), type: 'neg', max: 7 },
        ];

        // --- PESD SCORING ---
        // 10 Subscales, 3 items each. Range -4 to +4.
        const pesdScores = PESD_CATEGORIES.map((cat, i) => {
            // Items are sequential: 0,10,20 for cat 0; 1,11,21 for cat 1, etc.
            const indices = [i, i + 10, i + 20];
            const val = mean(indices, data.pesd);
            return {
                name: cat,
                val: val,
                type: val >= 0 ? 'pos' : 'neg', // Dynamic coloring based on value sign usually, or scale intent? 
                                              // PESD is bipolar. + is "functional/optimal", - is "dysfunctional".
                                              // So color depends on value.
                max: 4
            };
        });

        return { ippsScores, mtsData, ctScores, pesdScores };
    }, [data]);

    const downloadCsv = () => {
        if (history.length === 0) return;

        let csvContent = "data:text/csv;charset=utf-8,";
        csvContent += "ID,Data,Nome,Disciplina,IPPS_Fiducia,IPPS_Controllo,IPPS_Ansia,IPPS_Distrazione,MTS_Total,CT_Challenge,CT_Threat,PESD_Mean\n";

        history.forEach(row => {
            // Re-calculate basic metrics for CSV (simplified)
            // Ideally we store the calculated subscales, but for now we re-calc or just dump raw? 
            // Let's dump the aggregated scores we display.
            const iConf = mean(IPPS_SUBSCALES.confidence, row.ipps).toFixed(2);
            const iCont = mean(IPPS_SUBSCALES.control, row.ipps).toFixed(2);
            const iAnx = mean(IPPS_SUBSCALES.anxiety, row.ipps).toFixed(2);
            const iDist = mean(IPPS_SUBSCALES.distraction, row.ipps).toFixed(2);
            const mts = (row.mts.reduce((a,b)=>a+b,0)/row.mts.length).toFixed(2);
            const ctCh = mean(CT_SUBSCALES.challenge, row.ct).toFixed(2);
            const ctTh = mean(CT_SUBSCALES.threat, row.ct).toFixed(2);
            const pesd = (row.pesd.reduce((a,b)=>a+b,0)/row.pesd.length).toFixed(2);

            csvContent += `${row.id},${row.date},${row.name},${row.discipline},${iConf},${iCont},${iAnx},${iDist},${mts},${ctCh},${ctTh},${pesd}\n`;
        });

        const encodedUri = encodeURI(csvContent);
        const link = document.createElement("a");
        link.setAttribute("href", encodedUri);
        link.setAttribute("download", `flux_assessment_${new Date().toISOString().split('T')[0]}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    // Custom Tooltip
    const CustomTooltip = ({ active, payload }: any) => {
        if (active && payload && payload.length) {
            return (
                <div className="bg-white p-3 border border-gray-200 shadow-lg rounded-lg">
                    <p className="font-bold">{payload[0].payload.name}</p>
                    <p className="text-gray-600">Punteggio: <span className="font-mono font-bold">{Number(payload[0].value).toFixed(2)}</span></p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="space-y-12 animate-fade-in">
            {/* Header Area */}
            <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-red-600 flex flex-col md:flex-row justify-between items-center">
                <div>
                    <h2 className="text-2xl font-bold text-gray-900">Report Analitico</h2>
                    <p className="text-gray-500">Atleta: <span className="font-bold text-gray-900">{profile.name || "Non specificato"}</span></p>
                </div>
                <div className="flex gap-3 mt-4 md:mt-0">
                    <button
                        onClick={onSave}
                        disabled={!canSave}
                        className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold shadow-sm transition-all ${
                            canSave 
                            ? 'bg-gray-900 text-white hover:bg-black hover:shadow-md' 
                            : 'bg-gray-100 text-gray-400 cursor-not-allowed'
                        }`}
                    >
                        <Save size={18} />
                        Salva nel DB
                    </button>
                </div>
            </div>

            {/* Charts Grid */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

                {/* IPPS-24 Chart */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="text-lg font-bold text-gray-800 mb-1">IPPS-24</h3>
                    <p className="text-xs text-gray-500 mb-6">Scala 1-6. Ansia/Distrazione (Rosso) vs Fiducia/Controllo (Verde).</p>
                    <div className="h-[300px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart layout="vertical" data={results.ippsScores} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                                <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                                <XAxis type="number" domain={[0, 6]} hide />
                                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12, fontWeight: 600}} />
                                <Tooltip content={<CustomTooltip />} />
                                <Bar dataKey="val" radius={[0, 4, 4, 0]} barSize={30}>
                                    {results.ippsScores.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={entry.type === 'pos' ? COLORS.positive : COLORS.negative} />
                                    ))}
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* C&T and MTS Chart Combined or separate? Let's separate vertically but keep in same col or separate blocks */}
                <div className="space-y-8">
                    {/* C&T */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                        <h3 className="text-lg font-bold text-gray-800 mb-1">Challenge & Threat</h3>
