// Helper to calculate mean
const mean = (indices: number[], values: number[]) => {
    if (indices.length === 0) return 0;
    const sum = indices.reduce((acc, idx) => acc + values[idx], 0);
    return sum / indices.length;
};

// Colors
const COLORS = {
    positive: '#22c55e', // Green 500
    negative: '#ef4444', // Red 500
    neutral: '#9ca3af'   // Gray 400
};

export const ResultsTab: React.FC<ResultsTabProps> = ({ profile, data }) => {

    const results = useMemo(() => {
        // --- IPPS SCORING ---
        const ippsScores = [
            { name: 'Fiducia', val: mean(IPPS_SUBSCALES.confidence, data.ipps), type: 'pos', max: 6 },
            { name: 'Controllo (+)', val: mean(IPPS_SUBSCALES.control, data.ipps), type: 'pos', max: 6 },
            { name: 'Ansia', val: mean(IPPS_SUBSCALES.anxiety, data.ipps), type: 'neg', max: 6 },
            { name: 'Distrazione', val: mean(IPPS_SUBSCALES.distraction, data.ipps), type: 'neg', max: 6 },
        ];

        // --- MTS SCORING ---
        const mtsScore = data.mts.reduce((a, b) => a + b, 0) / data.mts.length;
        const mtsData = [
            { name: 'Mental Toughness', val: mtsScore, type: 'pos', max: 5 }
        ];

        // --- C&T SCORING ---
        const ctScores = [
            { name: 'Challenge (Sfida)', val: mean(CT_SUBSCALES.challenge, data.ct), type: 'pos', max: 7 },
            { name: 'Threat (Minaccia)', val: mean(CT_SUBSCALES.threat, data.ct), type: 'neg', max: 7 },
        ];

        // --- PESD SCORING ---
        const pesdScores = PESD_CATEGORIES.map((cat, i) => {
            const indices = [i, i + 10, i + 20];
            const val = mean(indices, data.pesd);
            return {
                name: cat,
                val: val,
                type: val >= 0 ? 'pos' : 'neg', 
                max: 4
            };
        });

        return { ippsScores, mtsData, ctScores, pesdScores };
    }, [data]);

    // Custom Tooltip
    const CustomTooltip = ({ active, payload }: any) => {
        if (active && payload && payload.length) {
            return (
                <div className="bg-white p-3 border border-gray-200 shadow-lg rounded-lg z-50">
                    <p className="font-bold">{payload[0].payload.name}</p>
                    <p className="text-gray-600">Punteggio: <span className="font-mono font-bold">{Number(payload[0].value).toFixed(2)}</span></p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="space-y-12 animate-fade-in pb-10">
            {/* Header Area */}
            <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-red-600 flex flex-col md:flex-row justify-between items-center">
                <div>
                    <h2 className="text-2xl font-bold text-gray-900">Report Analitico</h2>
                    <p className="text-gray-500">Atleta: <span className="font-bold text-gray-900">{profile.name || "N/D"}</span></p>
                </div>
                <div className="mt-2 text-sm text-gray-400">
                    Modalità Psicologo (Dashboard)
                </div>
            </div>

            {/* Charts Grid */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

                {/* IPPS-24 Chart */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="text-lg font-bold text-gray-800 mb-1">IPPS-24</h3>
                    <p className="text-xs text-gray-500 mb-6">Scala 1-6. Ansia/Distrazione (Rosso) vs Fiducia/Controllo (Verde).</p>
                    <div className="h-[300px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart layout="vertical" data={results.ippsScores} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                                <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                                <XAxis type="number" domain={[0, 6]} hide />
                                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12, fontWeight: 600}} />
                                <Tooltip content={<CustomTooltip />} />
                                <Bar dataKey="val" radius={[0, 4, 4, 0]} barSize={30}>
                                    {results.ippsScores.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={entry.type === 'pos' ? COLORS.positive : COLORS.negative} />
                                    ))}
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* C&T and MTS */}
                <div className="space-y-8">
                    {/* C&T */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                        <h3 className="text-lg font-bold text-gray-800 mb-1">Challenge & Threat</h3>
                        <p className="text-xs text-gray-500 mb-6">Scala 1-7. Minaccia (Rosso) vs Sfida (Verde).</p>
                        <div className="h-[180px]">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart layout="vertical" data={results.ctScores} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                                    <XAxis type="number" domain={[0, 7]} hide />
                                    <YAxis dataKey="name" type="category" width={120} tick={{fontSize: 12, fontWeight: 600}} />
                                    <Tooltip content={<CustomTooltip />} />
                                    <Bar dataKey="val" radius={[0, 4, 4, 0]} barSize={30}>
                                        {results.ctScores.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.type === 'pos' ? COLORS.positive : COLORS.negative} />
                                        ))}
                                    </Bar>
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* MTS */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                        <h3 className="text-lg font-bold text-gray-800 mb-1">Mental Toughness (MTS)</h3>
                        <p className="text-xs text-gray-500 mb-6">Scala 1-5.</p>
                        <div className="h-[80px]">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart layout="vertical" data={results.mtsData} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                                    <XAxis type="number" domain={[0, 5]} hide />
                                    <YAxis dataKey="name" type="category" width={120} tick={{fontSize: 12, fontWeight: 600}} />
                                    <Tooltip content={<CustomTooltip />} />
                                    <Bar dataKey="val" fill="#8884d8" radius={[0, 4, 4, 0]} barSize={30}>
                                         <Cell fill={COLORS.positive} />
                                    </Bar>
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </div>

            </div>

            {/* PESD Chart */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                <h3 className="text-lg font-bold text-gray-800 mb-1">PESD - Profilo Psicobiosociale</h3>
                <p className="text-xs text-gray-500 mb-6">Scala Bipolare -4 (Disfunzionale) a +4 (Funzionale). Barre a destra = Stati ottimali.</p>
                <div className="h-[500px]">
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart layout="vertical" data={results.pesdScores} margin={{ top: 5, right: 30, left: 100, bottom: 5 }}>
                            <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={true} />
                            <XAxis type="number" domain={[-4, 4]} ticks={[-4, -2, 0, 2, 4]} />
                            <YAxis dataKey="name" type="category" width={140} tick={{fontSize: 12, fontWeight: 600}} interval={0} />
                            <Tooltip content={<CustomTooltip />} />
                            <ReferenceLine x={0} stroke="#000" />
                            <Bar dataKey="val" barSize={25}>
                                {results.pesdScores.map((entry, index) => (
