    const [ippsData, setIppsData] = useState<number[]>(new Array(IPPS_ITEMS.length).fill(3));
    const [mtsData, setMtsData] = useState<number[]>(new Array(MTS_ITEMS.length).fill(3));
    const [ctData, setCtData] = useState<number[]>(new Array(CT_ITEMS.length).fill(4));
    const [pesdData, setPesdData] = useState<number[]>(new Array(PESD_ITEMS.length).fill(0));

    const handleLogin = (e: React.FormEvent) => {
        e.preventDefault();

        // Safe env access
        let envPass = '';
        if (typeof import.meta !== 'undefined' && (import.meta as any).env) {
            envPass = (import.meta as any).env.VITE_ADMIN_PASSWORD;
        } else if (typeof process !== 'undefined' && process.env) {
            envPass = process.env.VITE_ADMIN_PASSWORD || '';
        }

        if (password === envPass) {
            setIsAuthenticated(true);
            fetchRecords();
        } else {
            alert("Password errata");
        }
    };

    const fetchRecords = async () => {
        setIsLoading(true);
        const { data, error } = await supabase
            .from('assessments')
            .select('*')
            .order('created_at', { ascending: false });

        if (error) {
            console.error(error);
            alert("Errore nel caricamento dati: " + error.message);
        } else if (data) {
            // Map DB fields to our types (snake_case to camelCase mapping mostly handled manually)
            const mapped: AssessmentRecord[] = data.map(d => ({
                id: d.id,
                date: new Date(d.created_at).toLocaleDateString(),
                name: d.athlete_name,
                discipline: d.discipline,
                yearsOfPractice: d.years_of_practice,
                ipps: d.ipps,
                mts: d.mts,
                ct: d.ct,
                pesd: d.pesd
            }));
            setRecords(mapped);
            setFilteredRecords(mapped);
        }
        setIsLoading(false);
    };

    useEffect(() => {
        if (searchTerm === '') {
            setFilteredRecords(records);
        } else {
            const lower = searchTerm.toLowerCase();
            setFilteredRecords(records.filter(r => 
                r.name.toLowerCase().includes(lower) || 
                r.discipline.toLowerCase().includes(lower)
            ));
        }
    }, [searchTerm, records]);

    const selectRecord = (record: AssessmentRecord) => {
