import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, Cell 
} from 'recharts';
import { Download } from 'lucide-react';
import { AthleteProfile, QuestionnaireData } from '../types';
import { IPPS_SUBSCALES, CT_SUBSCALES, PESD_CATEGORIES } from '../constants';

interface ResultsTabProps {
    profile: AthleteProfile;
    data: QuestionnaireData;
}

// Colors
const COLORS = {
    positive: '#388BFD', // Blue for IPPS positive
    negative: '#F85149', // Red for IPPS negative / Threat
    challenge: '#3FB950', // Green for Challenge
    pesd: '#BC8CFF',     // Purple for PESD
    text: '#1F2937'
};

const mean = (indices: number[], values: number[]) => {
    if (indices.length === 0) return 0;
    const sum = indices.reduce((acc, idx) => acc + (values[idx] || 0), 0);
    return sum / indices.length;
};

export const ResultsTab: React.FC<ResultsTabProps> = ({ profile, data }) => {

    const results = useMemo(() => {
        // IPPS Calculation
        const ippsScores = [
            { name: '▲ Fiducia', val: mean(IPPS_SUBSCALES.confidence, data.ipps), fill: COLORS.positive },
            { name: '▲ Ctrl Arousal', val: mean(IPPS_SUBSCALES.control, data.ipps), fill: COLORS.positive },
            { name: '▼ Preoccupazione', val: mean(IPPS_SUBSCALES.worry, data.ipps), fill: COLORS.negative },
            { name: '▼ Dist. Conc.', val: mean(IPPS_SUBSCALES.distraction, data.ipps), fill: COLORS.negative },
        ];

        // MTS Calculation
        const mtsScore = data.mts.reduce((a, b) => a + b, 0) / data.mts.length;

        // CT Calculation
        const ctScores = [
            { name: 'Challenge', val: mean(CT_SUBSCALES.challenge, data.ct), fill: COLORS.challenge },
            { name: 'Threat', val: mean(CT_SUBSCALES.threat, data.ct), fill: COLORS.negative },
        ];

        // PESD Calculation
        const pesdScores = PESD_CATEGORIES.map((cat, i) => {
            const indices = [i, i + 10, i + 20];
            const val = mean(indices, data.pesd);
            return { name: cat, val: val, fill: COLORS.pesd };
        });

        // PESD Total
        const pesdTotal = pesdScores.reduce((acc, curr) => acc + curr.val, 0) / pesdScores.length;
        pesdScores.push({ name: 'PESD Totale', val: pesdTotal, fill: '#8957e5' }); // Darker purple

        return { ippsScores, mtsScore, ctScores, pesdScores };
    }, [data]);

    const downloadCSV = () => {
        const headers = [
            "Atleta", "Disciplina", "Data", "Email", "Telefono",
            "IPPS Fiducia", "IPPS Controllo", "IPPS Preoccupazione", "IPPS Distrazione",
            "MTS Total",
            "CT Challenge", "CT Threat",
            ...PESD_CATEGORIES, "PESD Totale"
        ];

        const row = [
            profile.name, profile.discipline, new Date().toLocaleDateString(), profile.email, profile.phone,
            results.ippsScores[0].val.toFixed(2), results.ippsScores[1].val.toFixed(2), results.ippsScores[2].val.toFixed(2), results.ippsScores[3].val.toFixed(2),
            results.mtsScore.toFixed(2),
            results.ctScores[0].val.toFixed(2), results.ctScores[1].val.toFixed(2),
            ...results.pesdScores.map(s => s.val.toFixed(2))
        ];

        const csvContent = "data:text/csv;charset=utf-8," + [headers.join(","), row.join(",")].join("\n");
        const encodedUri = encodeURI(csvContent);
        const link = document.createElement("a");
        link.setAttribute("href", encodedUri);
        link.setAttribute("download", `flux_assessment_${profile.name.replace(/\s+/g, '_')}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const CustomTooltip = ({ active, payload }: any) => {
        if (active && payload && payload.length) {
            return (
                <div className="bg-white p-2 border border-gray-200 shadow-lg rounded text-sm">
                    <p className="font-bold text-gray-800">{payload[0].payload.name}</p>
                    <p className="font-mono">{Number(payload[0].value).toFixed(2)}</p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="space-y-10 pb-20">
            <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-red-600 flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-bold text-gray-900">Analisi Profilo</h2>
                    <div className="flex flex-col gap-1 mt-1 text-sm text-gray-600">
                        <span>Atleta: <strong>{profile.name}</strong></span>
                        <span>Disciplina: {profile.discipline}</span>
                        <span>Email: {profile.email || '-'} | Tel: {profile.phone || '-'}</span>
                    </div>
                </div>
                <button onClick={downloadCSV} className="flex items-center gap-2 px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-lg transition-colors font-medium">
                    <Download size={18} /> Scarica CSV
                </button>
            </div>

            {/* Score Cards Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <div className="bg-blue-50 p-4 rounded-lg border border-blue-100">
                    <h4 className="font-bold text-blue-900 mb-2 border-b border-blue-200 pb-1">IPPS-24</h4>
                    <div className="space-y-1 text-sm">
                        {results.ippsScores.map(s => (
                            <div key={s.name} className="flex justify-between">
                                <span>{s.name}</span>
                                <span className="font-bold">{s.val.toFixed(2)}</span>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="bg-purple-50 p-4 rounded-lg border border-purple-100">
                    <h4 className="font-bold text-purple-900 mb-2 border-b border-purple-200 pb-1">MTS</h4>
                    <div className="flex justify-between items-center h-full pb-4">
                        <span className="text-sm">Mental Toughness</span>
                        <span className="text-2xl font-bold text-purple-700">{results.mtsScore.toFixed(2)}</span>
