import React, { useState, useEffect } from 'react';
import { Target, Search, Lock, Users, RefreshCw, Trash2, Filter } from 'lucide-react';
import { supabase, getEnvVar } from '../lib/supabase';
import { AssessmentRecord } from '../types';
import { ResultsTab } from '../components/ResultsTab';
import { IppsTab, MtsTab, CtTab } from '../components/Questionnaires';
import { PesdTab } from '../components/PesdTab';
import { IPPS_ITEMS, MTS_ITEMS, CT_ITEMS, PESD_ITEMS, DISCIPLINES } from '../constants';

export const DashboardPage = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(false);
    const [password, setPassword] = useState('');
    const [records, setRecords] = useState<AssessmentRecord[]>([]);
    const [filteredRecords, setFilteredRecords] = useState<AssessmentRecord[]>([]);
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [disciplineFilter, setDisciplineFilter] = useState('Tutte');
    const [activeTab, setActiveTab] = useState(4); // Default to Results

    // Selected data state
    const [currentProfile, setCurrentProfile] = useState({ name: '', discipline: '', yearsOfPractice: 0, email: '', phone: '' });
    const [ippsData, setIppsData] = useState<number[]>(new Array(IPPS_ITEMS.length).fill(3));
    const [mtsData, setMtsData] = useState<number[]>(new Array(MTS_ITEMS.length).fill(3));
    const [ctData, setCtData] = useState<number[]>(new Array(CT_ITEMS.length).fill(4));
    const [pesdData, setPesdData] = useState<number[]>(new Array(PESD_ITEMS.length).fill(0));

    const handleLogin = (e: React.FormEvent) => {
        e.preventDefault();
        // Fallback to 'admin' if env var is missing in preview environment
        const envPass = getEnvVar('VITE_ADMIN_PASSWORD') || 'admin';
        if (password === envPass) {
            setIsAuthenticated(true);
            fetchRecords();
        } else {
            alert("Password errata");
        }
    };

    const fetchRecords = async () => {
        setIsLoading(true);
        const { data, error } = await supabase
            .from('assessments')
            .select('*')
            .order('created_at', { ascending: false });

        if (error) {
            console.error(error);
            alert("Errore nel caricamento dati: " + error.message);
        } else if (data) {
            const mapped: AssessmentRecord[] = data.map(d => ({
                id: d.id,
                date: new Date(d.created_at).toLocaleDateString(),
                name: d.athlete_name,
                discipline: d.discipline,
                yearsOfPractice: d.years_of_practice,
                email: d.email || '',
                phone: d.phone || '',
                ipps: d.ipps,
                mts: d.mts,
                ct: d.ct,
                pesd: d.pesd
            }));
            setRecords(mapped);
            // Apply current filters immediately
            applyFilters(mapped, searchTerm, disciplineFilter);
        }
        setIsLoading(false);
    };

    const applyFilters = (data: AssessmentRecord[], search: string, disc: string) => {
        let res = data;
        if (search) {
            const lower = search.toLowerCase();
            res = res.filter(r => r.name.toLowerCase().includes(lower));
        }
        if (disc !== 'Tutte') {
            res = res.filter(r => r.discipline === disc);
        }
        setFilteredRecords(res);
    };

    useEffect(() => {
        applyFilters(records, searchTerm, disciplineFilter);
    }, [searchTerm, disciplineFilter, records]);

    const selectRecord = (record: AssessmentRecord) => {
        setSelectedId(record.id);
        setCurrentProfile({
            name: record.name,
            discipline: record.discipline,
            yearsOfPractice: record.yearsOfPractice,
            email: record.email,
            phone: record.phone
        });
        setIppsData(record.ipps);
        setMtsData(record.mts);
        setCtData(record.ct);
        setPesdData(record.pesd);
        setActiveTab(4); // Switch to Results view
    };

    const handleDelete = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (confirm("Sei sicuro di voler eliminare definitivamente questo record?")) {
            const { error } = await supabase.from('assessments').delete().eq('id', id);
            if (error) {
                alert("Errore eliminazione");
            } else {
                const updated = records.filter(r => r.id !== id);
                setRecords(updated);
                if (selectedId === id) setSelectedId(null);
            }
        }
    };

    if (!isAuthenticated) {
        return (
            <div className="min-h-screen bg-gray-900 flex items-center justify-center p-4">
                <form onSubmit={handleLogin} className="bg-white p-8 rounded-2xl shadow-2xl max-w-sm w-full">
                    <div className="flex justify-center mb-6 text-gray-900">
                        <Lock size={48} />
                    </div>
                    <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">Accesso Psicologo</h2>
                    <input
                        type="password"
                        placeholder="Password Amministratore"
                        className="w-full p-3 border border-gray-300 rounded-lg mb-4 outline-none focus:ring-2 focus:ring-blue-500"
                        value={password}
                        onChange={e => setPassword(e.target.value)}
                    />
                    <button className="w-full bg-gray-900 text-white p-3 rounded-lg font-bold hover:bg-black transition">
                        Entra
                    </button>
                    <p className="mt-4 text-xs text-center text-gray-400">
                        Password richiesta per accedere ai dati sensibili. <br/>
                        (Default preview: <strong>admin</strong>)
                    </p>
                </form>
            </div>
        );
    }

    return (
        <div className="flex h-screen overflow-hidden bg-gray-100 font-sans">
            {/* Left Panel: List of Assessments */}
            <aside className="w-96 bg-white border-r border-gray-200 flex flex-col z-10 shadow-xl">
                <div className="p-4 border-b border-gray-200 bg-gray-50">
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="font-bold text-gray-800 flex items-center gap-2">
                            <Users size={18} /> Database Atleti
                        </h2>
                        <button onClick={fetchRecords} className="p-2 hover:bg-gray-200 rounded-full transition" title="Aggiorna">
                            <RefreshCw size={16} className={isLoading ? 'animate-spin' : ''} />
                        </button>
                    </div>
                    <div className="space-y-3">
                        <div className="relative">
                            <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
                            <input 
                                type="text" 
                                placeholder="Cerca atleta..." 
                                className="w-full pl-9 pr-3 py-2 bg-white border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <div className="flex items-center gap-2 bg-white border border-gray-300 rounded-lg px-3 py-1">
                            <Filter size={14} className="text-gray-400" />
                            <select 
                                className="w-full py-1 text-sm bg-transparent outline-none cursor-pointer"
                                value={disciplineFilter}
                                onChange={(e) => setDisciplineFilter(e.target.value)}
                            >
                                <option value="Tutte">Tutte le discipline</option>
                                {DISCIPLINES.map(d => <option key={d} value={d}>{d}</option>)}
                            </select>
                        </div>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto">
                    {filteredRecords.length === 0 ? (
                        <div className="p-8 text-center text-gray-400 text-sm">Nessun assessment trovato.</div>
                    ) : (
                        <ul>
                            {filteredRecords.map(rec => (
                                <li 
                                    key={rec.id}
                                    onClick={() => selectRecord(rec)}
                                    className={`p-4 border-b border-gray-100 cursor-pointer hover:bg-blue-50 transition-colors relative group ${selectedId === rec.id ? 'bg-blue-50 border-l-4 border-blue-600' : ''}`}
                                >
                                    <div className="font-bold text-gray-800">{rec.name}</div>
                                    <div className="text-xs text-gray-500 flex flex-col gap-1 mt-1">
                                        <div className="flex justify-between">
                                            <span>{rec.discipline}</span>
                                            <span>{rec.date}</span>
                                        </div>
                                    </div>
                                    <button 
                                        onClick={(e) => handleDelete(rec.id, e)}
                                        className="absolute right-2 top-3 p-2 text-gray-300 hover:text-red-600 opacity-0 group-hover:opacity-100 transition-opacity"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </li>
                            ))}
                        </ul>
                    )}
                </div>
            </aside>

            {/* Main Area: Detailed View */}
            <main className="flex-1 flex flex-col overflow-hidden bg-gray-50">
                {selectedId ? (
                    <>
                         {/* Tabs Navigation */}
                        <div className="bg-white border-b border-gray-200 px-6 py-2 overflow-x-auto">
                             <div className="flex space-x-6 text-sm font-medium whitespace-nowrap">
                                <button onClick={() => setActiveTab(4)} className={`py-3 border-b-2 ${activeTab === 4 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>Risultati & Analisi</button>
                                <button onClick={() => setActiveTab(0)} className={`py-3 border-b-2 ${activeTab === 0 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>IPPS-24</button>
                                <button onClick={() => setActiveTab(1)} className={`py-3 border-b-2 ${activeTab === 1 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>MTS</button>
                                <button onClick={() => setActiveTab(2)} className={`py-3 border-b-2 ${activeTab === 2 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>C&T</button>
                                <button onClick={() => setActiveTab(3)} className={`py-3 border-b-2 ${activeTab === 3 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>PESD</button>
                             </div>
                        </div>

                        {/* Content */}
                        <div className="flex-1 overflow-y-auto p-8">
                            <div className="max-w-6xl mx-auto">
                                {activeTab === 4 && <ResultsTab profile={currentProfile} data={{ ipps: ippsData, mts: mtsData, ct: ctData, pesd: pesdData }} />}
                                {/* Read-only views of inputs */}
                                <div className={activeTab === 0 ? 'block pointer-events-none opacity-90' : 'hidden'}><IppsTab data={ippsData} onChange={()=>{}} /></div>
                                <div className={activeTab === 1 ? 'block pointer-events-none opacity-90' : 'hidden'}><MtsTab data={mtsData} onChange={()=>{}} /></div>
                                <div className={activeTab === 2 ? 'block pointer-events-none opacity-90' : 'hidden'}><CtTab data={ctData} onChange={()=>{}} /></div>
                                <div className={activeTab === 3 ? 'block pointer-events-none opacity-90' : 'hidden'}><PesdTab data={pesdData} onChange={()=>{}} /></div>
                            </div>
                        </div>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-gray-400">
                        <Target size={64} className="mb-4 opacity-20" />
                        <p className="text-xl font-medium">Seleziona un atleta dal database per visualizzare l'analisi.</p>
                    </div>
                )}
            </main>
        </div>
    );
};

import React, { useState } from 'react';
import { Target, Brain, Swords, Activity, Send, CheckCircle, AlertCircle, Lock } from 'lucide-react';
import { Sidebar } from '../components/Sidebar';
import { IppsTab, MtsTab, CtTab } from '../components/Questionnaires';
import { PesdTab } from '../components/PesdTab';
import { IPPS_ITEMS, MTS_ITEMS, CT_ITEMS, PESD_ITEMS } from '../constants';
import { AthleteProfile } from '../types';
import { supabase } from '../lib/supabase';

export const AthletePage = () => {
  const [profile, setProfile] = useState<AthleteProfile>({
    name: '',
    discipline: 'Carabina',
    yearsOfPractice: 0,
    email: '',
    phone: ''
  });

  const [ippsData, setIppsData] = useState<number[]>(new Array(IPPS_ITEMS.length).fill(3));
  const [mtsData, setMtsData] = useState<number[]>(new Array(MTS_ITEMS.length).fill(3));
  const [ctData, setCtData] = useState<number[]>(new Array(CT_ITEMS.length).fill(4));
  const [pesdData, setPesdData] = useState<number[]>(new Array(PESD_ITEMS.length).fill(0));

  const [activeTab, setActiveTab] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleProfileChange = (field: keyof AthleteProfile, value: string | number) => {
    setProfile(prev => ({ ...prev, [field]: value }));
    if (errorMsg) setErrorMsg(null);
  };

  const updateQuestionnaire = (setter: React.Dispatch<React.SetStateAction<number[]>>, index: number, val: number) => {
    setter(prev => {
      const copy = [...prev];
      copy[index] = val;
      return copy;
    });
  };

  const validate = () => {
    if (!profile.name.trim()) return "Il campo 'Nome e Cognome' è obbligatorio.";
    if (!profile.email.trim() && !profile.phone.trim()) return "È necessario inserire almeno un contatto (Email o Telefono).";
    return null;
  };

  const handleSubmit = async () => {
    const error = validate();
    if (error) {
      setErrorMsg(error);
      window.scrollTo(0, 0);
      return;
    }

    setIsSubmitting(true);

    try {
      const { error } = await supabase.from('assessments').insert({
        athlete_name: profile.name,
        discipline: profile.discipline,
        years_of_practice: profile.yearsOfPractice,
        email: profile.email,
        phone: profile.phone,
        ipps: ippsData,
        mts: mtsData,
        ct: ctData,
        pesd: pesdData
      });

      if (error) throw error;
      setSubmitted(true);
    } catch (err) {
      console.error(err);
      setErrorMsg("Errore di connessione al database. Riprova tra poco.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="bg-white max-w-md w-full p-8 rounded-2xl shadow-lg text-center">
            <div className="flex justify-center mb-6">
                <CheckCircle className="w-20 h-20 text-green-500" />
            </div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">Grazie {profile.name}!</h1>
            <p className="text-gray-600 mb-8">
                I tuoi dati sono stati inviati correttamente al Dr. Macalluso.
            </p>
            <div className="flex flex-col gap-4">
                <button 
                    onClick={() => window.location.reload()} 
                    className="text-sm text-gray-400 hover:text-gray-600 underline"
                >
                    Compila un altro test
                </button>
                <a href="#/dashboard" className="inline-flex items-center justify-center gap-2 px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 font-bold transition-colors">
                    <Lock size={16} /> Vai alla Dashboard
                </a>
            </div>
        </div>
      </div>
    );
  }

  const tabs = [
    { id: 0, label: 'IPPS-24', icon: Target, component: <IppsTab data={ippsData} onChange={(i, v) => updateQuestionnaire(setIppsData, i, v)} /> },
    { id: 1, label: 'MTS', icon: Brain, component: <MtsTab data={mtsData} onChange={(i, v) => updateQuestionnaire(setMtsData, i, v)} /> },
    { id: 2, label: 'C&T', icon: Swords, component: <CtTab data={ctData} onChange={(i, v) => updateQuestionnaire(setCtData, i, v)} /> },
    { id: 3, label: 'PESD', icon: Activity, component: <PesdTab data={pesdData} onChange={(i, v) => updateQuestionnaire(setPesdData, i, v)} /> }
  ];

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-gray-50 font-sans">
        {/* Sidebar always visible on desktop */}
        <div className="hidden md:block">
            <Sidebar profile={profile} onChange={handleProfileChange} />
        </div>

        {/* Mobile Header */}
        <div className="md:hidden bg-white border-b border-gray-200 p-4 sticky top-0 z-20">
             <div className="flex items-center gap-2 font-black text-gray-900 mb-4">
                <span className="bg-yellow-400 p-1 rounded text-white"><Target size={16} fill="currentColor" /></span>
                FLUX Assessment
            </div>
            <div className="space-y-2">
                <input 
                    type="text" 
                    placeholder="Nome e Cognome *" 
                    className="w-full p-2 border border-gray-300 rounded"
                    value={profile.name}
                    onChange={(e) => handleProfileChange('name', e.target.value)}
                />
            </div>
        </div>

        <main className="flex-1 flex flex-col h-full overflow-hidden w-full relative">

            {/* Validation Banner */}
            {errorMsg && (
                <div className="bg-red-500 text-white px-6 py-3 flex items-center gap-3 animate-pulse shadow-md">
                    <AlertCircle size={20} />
                    <span className="font-bold">{errorMsg}</span>
                </div>
            )}

            <div className="bg-white border-b border-gray-200 px-6 py-2 overflow-x-auto scrollbar-hide flex-shrink-0">
                <div className="flex space-x-8 min-w-max">
                    {tabs.map((tab) => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`flex items-center gap-2 py-4 px-1 border-b-2 transition-colors font-medium text-sm
                        ${activeTab === tab.id ? 'border-red-600 text-red-600' : 'border-transparent text-gray-500'}`}
                    >
                        <tab.icon size={18} />
                        {tab.label}
                    </button>
                    ))}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8 pb-32">
                <div className="max-w-4xl mx-auto">
                    {tabs[activeTab].component}
                </div>
            </div>

            {/* Bottom Floating Submit Bar */}
            <div className="absolute bottom-0 left-0 w-full bg-white border-t border-gray-200 p-4 shadow-lg z-10 flex justify-between items-center">
                 <div className="flex flex-col">
                    <div className="text-xs text-gray-500 hidden md:block">
                        Completa tutti i tab prima di inviare.
                    </div>
                    {/* Link "nascosto" per accesso rapido in preview */}
                    <a href="#/dashboard" className="text-xs text-gray-300 hover:text-blue-500 flex items-center gap-1 mt-1 font-medium transition-colors cursor-pointer">
                        <Lock size={12} /> Area Psicologo
                    </a>
                 </div>
                 <button
                    onClick={handleSubmit}
                    disabled={isSubmitting}
                    className="w-full md:w-auto bg-green-600 text-white px-8 py-3 rounded-lg font-bold shadow-md hover:bg-green-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                 >
                    {isSubmitting ? 'Invio in corso...' : (
                        <>
                            <Send size={18} /> Invia Assessment
                        </>
                    )}
                 </button>
            </div>
        </main>
    </div>
  );
};

