        } else if (data) {
            const mapped: AssessmentRecord[] = data.map(d => ({
                id: d.id,
                date: new Date(d.created_at).toLocaleDateString(),
                name: d.athlete_name,
                discipline: d.discipline,
                yearsOfPractice: d.years_of_practice,
                email: d.email || '',
                phone: d.phone || '',
                ipps: d.ipps,
                mts: d.mts,
                ct: d.ct,
                pesd: d.pesd
            }));
            setRecords(mapped);
            // Apply current filters immediately
            applyFilters(mapped, searchTerm, disciplineFilter);
        }
        setIsLoading(false);
    };

    const applyFilters = (data: AssessmentRecord[], search: string, disc: string) => {
        let res = data;
        if (search) {
            const lower = search.toLowerCase();
            res = res.filter(r => r.name.toLowerCase().includes(lower));
        }
        if (disc !== 'Tutte') {
            res = res.filter(r => r.discipline === disc);
        }
        setFilteredRecords(res);
    };

    useEffect(() => {
        applyFilters(records, searchTerm, disciplineFilter);
    }, [searchTerm, disciplineFilter, records]);

    const selectRecord = (record: AssessmentRecord) => {
        setSelectedId(record.id);
        setCurrentProfile({
            name: record.name,
            discipline: record.discipline,
            yearsOfPractice: record.yearsOfPractice,
            email: record.email,
            phone: record.phone
        });
        setIppsData(record.ipps);
        setMtsData(record.mts);
        setCtData(record.ct);
        setPesdData(record.pesd);
        setActiveTab(4); // Switch to Results view
    };

    const handleDelete = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (confirm("Sei sicuro di voler eliminare definitivamente questo record?")) {
            const { error } = await supabase.from('assessments').delete().eq('id', id);
            if (error) {
                alert("Errore eliminazione");
            } else {
                const updated = records.filter(r => r.id !== id);
                setRecords(updated);
                if (selectedId === id) setSelectedId(null);
            }
        }
    };

    if (!isAuthenticated) {
        return (
            <div className="min-h-screen bg-gray-900 flex items-center justify-center p-4">
                <form onSubmit={handleLogin} className="bg-white p-8 rounded-2xl shadow-2xl max-w-sm w-full">
                    <div className="flex justify-center mb-6 text-gray-900">
                        <Lock size={48} />
                    </div>
                    <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">Accesso Psicologo</h2>
                    <input
                        type="password"
                        placeholder="Password Amministratore"
                        className="w-full p-3 border border-gray-300 rounded-lg mb-4 outline-none focus:ring-2 focus:ring-blue-500"
                        value={password}
                        onChange={e => setPassword(e.target.value)}
                    />
                    <button className="w-full bg-gray-900 text-white p-3 rounded-lg font-bold hover:bg-black transition">
                        Entra
                    </button>
                    <div className="mt-4 text-center">
                        <p className="text-xs text-gray-400">Password richiesta per accedere ai dati sensibili.</p>
                        <p className="text-xs text-blue-400 font-mono mt-2 bg-gray-800 p-1 rounded inline-block">Default: admin</p>
                    </div>
                </form>
            </div>
        );
    }

    return (
        <div className="flex h-screen overflow-hidden bg-gray-100 font-sans">
            {/* Left Panel: List of Assessments */}
            <aside className="w-96 bg-white border-r border-gray-200 flex flex-col z-10 shadow-xl">
                <div className="p-4 border-b border-gray-200 bg-gray-50">
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="font-bold text-gray-800 flex items-center gap-2">
                            <Users size={18} /> Database Atleti
                        </h2>
                        <button onClick={fetchRecords} className="p-2 hover:bg-gray-200 rounded-full transition" title="Aggiorna">
                            <RefreshCw size={16} className={isLoading ? 'animate-spin' : ''} />
                        </button>
                    </div>
                    <div className="space-y-3">
                        <div className="relative">
                            <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
                            <input 
                                type="text" 
                                placeholder="Cerca atleta..." 
                                className="w-full pl-9 pr-3 py-2 bg-white border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <div className="flex items-center gap-2 bg-white border border-gray-300 rounded-lg px-3 py-1">
                            <Filter size={14} className="text-gray-400" />
                            <select 
                                className="w-full py-1 text-sm bg-transparent outline-none cursor-pointer"
                                value={disciplineFilter}
                                onChange={(e) => setDisciplineFilter(e.target.value)}
                            >
                                <option value="Tutte">Tutte le discipline</option>
                                {DISCIPLINES.map(d => <option key={d} value={d}>{d}</option>)}
                            </select>
                        </div>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto">
                    {filteredRecords.length === 0 ? (
                        <div className="p-8 text-center text-gray-400 text-sm">Nessun assessment trovato.</div>
                    ) : (
                        <ul>
                            {filteredRecords.map(rec => (
                                <li 
                                    key={rec.id}
                                    onClick={() => selectRecord(rec)}
                                    className={`p-4 border-b border-gray-100 cursor-pointer hover:bg-blue-50 transition-colors relative group ${selectedId === rec.id ? 'bg-blue-50 border-l-4 border-blue-600' : ''}`}
                                >
                                    <div className="font-bold text-gray-800">{rec.name}</div>
                                    <div className="text-xs text-gray-500 flex flex-col gap-1 mt-1">
                                        <div className="flex justify-between">
                                            <span>{rec.discipline}</span>
                                            <span>{rec.date}</span>
                                        </div>
                                    </div>
                                    <button 
                                        onClick={(e) => handleDelete(rec.id, e)}
                                        className="absolute right-2 top-3 p-2 text-gray-300 hover:text-red-600 opacity-0 group-hover:opacity-100 transition-opacity"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </li>
                            ))}
                        </ul>
                    )}
                </div>
            </aside>

            {/* Main Area: Detailed View */}
            <main className="flex-1 flex flex-col overflow-hidden bg-gray-50">
                {selectedId ? (
                    <>
                         {/* Tabs Navigation */}
                        <div className="bg-white border-b border-gray-200 px-6 py-2 overflow-x-auto">
                             <div className="flex space-x-6 text-sm font-medium whitespace-nowrap">
                                <button onClick={() => setActiveTab(4)} className={`py-3 border-b-2 ${activeTab === 4 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>Risultati & Analisi</button>
                                <button onClick={() => setActiveTab(0)} className={`py-3 border-b-2 ${activeTab === 0 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>IPPS-24</button>
                                <button onClick={() => setActiveTab(1)} className={`py-3 border-b-2 ${activeTab === 1 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>MTS</button>
                                <button onClick={() => setActiveTab(2)} className={`py-3 border-b-2 ${activeTab === 2 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>C&T</button>
                                <button onClick={() => setActiveTab(3)} className={`py-3 border-b-2 ${activeTab === 3 ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500'}`}>PESD</button>
                             </div>
                        </div>

                        {/* Content */}
                        <div className="flex-1 overflow-y-auto p-8">
                            <div className="max-w-6xl mx-auto">
                                {activeTab === 4 && <ResultsTab profile={currentProfile} data={{ ipps: ippsData, mts: mtsData, ct: ctData, pesd: pesdData }} />}
                                {/* Read-only views of inputs */}
                                <div className={activeTab === 0 ? 'block pointer-events-none opacity-90' : 'hidden'}><IppsTab data={ippsData} onChange={()=>{}} /></div>
                                <div className={activeTab === 1 ? 'block pointer-events-none opacity-90' : 'hidden'}><MtsTab data={mtsData} onChange={()=>{}} /></div>
                                <div className={activeTab === 2 ? 'block pointer-events-none opacity-90' : 'hidden'}><CtTab data={ctData} onChange={()=>{}} /></div>
                                <div className={activeTab === 3 ? 'block pointer-events-none opacity-90' : 'hidden'}><PesdTab data={pesdData} onChange={()=>{}} /></div>
                            </div>
                        </div>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-gray-400">
                        <Target size={64} className="mb-4 opacity-20" />
                        <p className="text-xl font-medium">Seleziona un atleta dal database per visualizzare l'analisi.</p>
                    </div>
                )}
            </main>
        </div>
    );
};

