      return { data: [], error: null };
    }
    try {
      const parsedData = JSON.parse(data);
      // Simplify the check. If the data is an array, we're returning it. Otherwise, return an empty array.
      if (Array.isArray(parsedData)) {
        return { data: parsedData, error: null };
      } else {
        return { data: [], error: null }; // or throw an error, depending on the desired behavior
      }
    } catch (e) {
      console.error("Error parsing data from localStorage:", e);
      return { data: [], error: new Error('Error parsing local data') }; // Handle parse errors
    }
