        }

        parsedData.push(data);
        localStorage.setItem(this.tableName, JSON.stringify(parsedData));
        return { data: data, error: null };  // Return data as confirmation
    } catch (e) {
        console.error("Error inserting data into localStorage:", e);
        return { data: null, error: new Error('Error inserting into local storage') };  // Handle errors
    }
  }
}

let supabaseClient;
if (envUrl && envAnonKey) {
