    const getLocalData = () => {
        try {
            const str = localStorage.getItem(STORAGE_KEY);
            return str ? JSON.parse(str) : [];
        } catch (e) { 
            console.error("Error reading local storage", e);
            return []; 
        }
    };

    const saveLocalData = (data: any[]) => {
        try {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
        } catch (e) {
            console.error("Error saving to local storage", e);
        }
    };

    // Helper for unique IDs
    const generateId = () => {
        return Date.now().toString(36) + Math.random().toString(36).substr(2);
    };

    // Mock Client Interface mimicking Supabase
    supabaseClient = {
        from: (table: string) => {
            return {
                select: (columns: string = '*') => {
                    return {
                        order: (col: string, { ascending }: any = { ascending: true }) => {
                            const data = getLocalData();
                            // Simple sort
                            data.sort((a: any, b: any) => {
                                const valA = a[col];
                                const valB = b[col];
                                if (valA < valB) return ascending ? -1 : 1;
                                if (valA > valB) return ascending ? 1 : -1;
                                return 0;
                            });
                            return Promise.resolve({ data, error: null });
                        }
                    };
                },
                insert: (recordOrRecords: any) => {
                    const data = getLocalData();
                    const records = Array.isArray(recordOrRecords) ? recordOrRecords : [recordOrRecords];

                    const newRecords = records.map((r: any) => ({
                        id: generateId(),
                        created_at: new Date().toISOString(),
                        ...r
                    }));

                    const updatedData = [...data, ...newRecords];
                    saveLocalData(updatedData);

                    return Promise.resolve({ data: newRecords, error: null });
                },
                delete: () => {
                    return {
                        eq: (col: string, val: any) => {
                            let data = getLocalData();
                            const initialLen = data.length;
                            data = data.filter((item: any) => item[col] !== val);

                            if (data.length !== initialLen) {
                                saveLocalData(data);
                            }
                            return Promise.resolve({ error: null });
                        }
                    };
                }
            };
        }
    } as any;
}

