interface SliderItemProps {
    label: string;
    value: number;
    min: number;
    max: number;
    labels: string[];
    onChange: (val: number) => void;
}

const SliderItem: React.FC<SliderItemProps> = ({ label, value, min, max, labels, onChange }) => {
