import React, { useState } from 'react';
import { Target, Brain, Swords, Activity, Send, CheckCircle, AlertCircle, Lock, Info } from 'lucide-react';
import { Sidebar } from '../components/Sidebar';
import { IppsTab, MtsTab, CtTab } from '../components/Questionnaires';
import { PesdTab } from '../components/PesdTab';
import { IPPS_ITEMS, MTS_ITEMS, CT_ITEMS, PESD_ITEMS } from '../constants';
import { AthleteProfile } from '../types';
import { supabase } from '../lib/supabase';

export const AthletePage = () => {
  const [profile, setProfile] = useState<AthleteProfile>({
    name: '',
    discipline: 'Carabina',
    yearsOfPractice: 0,
    email: '',
    phone: ''
  });

  const [ippsData, setIppsData] = useState<number[]>(new Array(IPPS_ITEMS.length).fill(3));
  const [mtsData, setMtsData] = useState<number[]>(new Array(MTS_ITEMS.length).fill(3));
  const [ctData, setCtData] = useState<number[]>(new Array(CT_ITEMS.length).fill(4));
  const [pesdData, setPesdData] = useState<number[]>(new Array(PESD_ITEMS.length).fill(0));

  const [activeTab, setActiveTab] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleProfileChange = (field: keyof AthleteProfile, value: string | number) => {
    setProfile(prev => ({ ...prev, [field]: value }));
    if (errorMsg) setErrorMsg(null);
  };

  const updateQuestionnaire = (setter: React.Dispatch<React.SetStateAction<number[]>>, index: number, val: number) => {
    setter(prev => {
      const copy = [...prev];
      copy[index] = val;
      return copy;
    });
  };

  const validate = () => {
    if (!profile.name.trim()) return "Il campo 'Nome e Cognome' è obbligatorio.";
    if (!profile.email.trim() && !profile.phone.trim()) return "È necessario inserire almeno un contatto (Email o Telefono).";
    return null;
  };

  const handleSubmit = async () => {
    const errorValidation = validate();
    if (errorValidation) {
      setErrorMsg(errorValidation);
      window.scrollTo(0, 0);
      return;
    }

    setIsSubmitting(true);
    setErrorMsg(null);

    try {
      const { error } = await supabase.from('assessments').insert({
        athlete_name: profile.name,
        discipline: profile.discipline,
        years_of_practice: profile.yearsOfPractice,
        email: profile.email,
        phone: profile.phone,
        ipps: ippsData,
        mts: mtsData,
        ct: ctData,
        pesd: pesdData
      });

      if (error) {
          console.error("Supabase Error:", error);
          if (error.code === '42P01') {
              setErrorMsg("⚠️ CONFIGURAZIONE DATABASE MANCANTE: La tabella 'assessments' non esiste. Esegui lo script SQL fornito nella chat.");
          } else {
              setErrorMsg("Errore durante il salvataggio: " + error.message);
          }
          return;
      }

      setSubmitted(true);
    } catch (err) {
      console.error("Unexpected Error:", err);
      setErrorMsg("Errore imprevisto di connessione. Controlla la console per dettagli.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="bg-white max-w-md w-full p-8 rounded-2xl shadow-lg text-center">
            <div className="flex justify-center mb-6">
                <CheckCircle className="w-20 h-20 text-green-500" />
            </div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">Grazie {profile.name}!</h1>
            <p className="text-gray-600 mb-8">
                I tuoi dati sono stati inviati correttamente al Dr. Massimiliano Di Liborio.
            </p>
            <div className="flex flex-col gap-4">
                <button 
                    onClick={() => window.location.reload()} 
                    className="text-sm text-gray-400 hover:text-gray-600 underline"
                >
                    Compila un altro test
                </button>
                <a href="#/dashboard" className="inline-flex items-center justify-center gap-2 px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 font-bold transition-colors">
                    <Lock size={16} /> Vai alla Dashboard
                </a>
            </div>
        </div>
      </div>
    );
  }

  const tabs = [
    { id: 0, label: 'IPPS-24', icon: Target, component: <IppsTab data={ippsData} onChange={(i, v) => updateQuestionnaire(setIppsData, i, v)} /> },
    { id: 1, label: 'MTS', icon: Brain, component: <MtsTab data={mtsData} onChange={(i, v) => updateQuestionnaire(setMtsData, i, v)} /> },
    { id: 2, label: 'C&T', icon: Swords, component: <CtTab data={ctData} onChange={(i, v) => updateQuestionnaire(setCtData, i, v)} /> },
    { id: 3, label: 'PESD', icon: Activity, component: <PesdTab data={pesdData} onChange={(i, v) => updateQuestionnaire(setPesdData, i, v)} /> }
  ];

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-gray-50 font-sans">
        {/* Sidebar always visible on desktop */}
        <div className="hidden md:block">
            <Sidebar profile={profile} onChange={handleProfileChange} />
        </div>

        {/* Mobile Header */}
        <div className="md:hidden bg-white border-b border-gray-200 p-4 sticky top-0 z-20">
             <div className="flex items-center gap-2 font-black text-gray-900 mb-4">
                <span className="bg-yellow-400 p-1 rounded text-white"><Target size={16} fill="currentColor" /></span>
                FLUX Assessment
            </div>
            <div className="space-y-2">
                <input 
                    type="text" 
                    placeholder="Nome e Cognome *" 
                    className="w-full p-2 border border-gray-300 rounded"
                    value={profile.name}
                    onChange={(e) => handleProfileChange('name', e.target.value)}
                />
            </div>
        </div>

        <main className="flex-1 flex flex-col h-full overflow-hidden w-full relative">

            {/* Validation Banner */}
            {errorMsg && (
                <div className="bg-red-500 text-white px-6 py-3 flex items-center gap-3 animate-pulse shadow-md">
                    <AlertCircle size={20} />
                    <span className="font-bold">{errorMsg}</span>
                </div>
            )}

            {/* General Instructions Banner */}
            <div className="bg-amber-50 border-b border-amber-100 p-4 flex gap-3 items-start">
                <div className="bg-amber-100 p-2 rounded-full text-amber-600 mt-0.5 shrink-0">
                    <Info size={20} />
                </div>
                <div className="text-sm text-amber-900">
                    <p className="font-bold mb-1">Istruzioni importanti:</p>
                    <p className="leading-relaxed">
                        Qui in basso sono presenti <strong>4 test differenti</strong> (scorri le schede per vederli tutti). 
                        È necessario <strong>compilarli tutti e 4</strong>. 
                        Una volta completati, premi il tasto verde <strong>"Invia Assessment"</strong> in basso a destra per salvare i dati.
                    </p>
                </div>
            </div>

            <div className="bg-white border-b border-gray-200 px-6 py-2 overflow-x-auto scrollbar-hide flex-shrink-0">
                <div className="flex space-x-8 min-w-max">
                    {tabs.map((tab) => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`flex items-center gap-2 py-4 px-1 border-b-2 transition-colors font-medium text-sm
                        ${activeTab === tab.id ? 'border-red-600 text-red-600' : 'border-transparent text-gray-500'}`}
                    >
                        <tab.icon size={18} />
                        {tab.label}
                    </button>
                    ))}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8 pb-32">
                <div className="max-w-4xl mx-auto">
                    {tabs[activeTab].component}
                </div>
            </div>

            {/* Bottom Floating Submit Bar */}
            <div className="absolute bottom-0 left-0 w-full bg-white border-t border-gray-200 p-4 shadow-lg z-10 flex justify-between items-center">
                 <div className="flex flex-col">
                    <div className="text-xs text-gray-500 hidden md:block">
                        Completa tutti i tab prima di inviare.
                    </div>
                    {/* Link "nascosto" per accesso rapido in preview */}
                    <a href="#/dashboard" className="text-xs text-gray-300 hover:text-blue-500 flex items-center gap-1 mt-1 font-medium transition-colors cursor-pointer">
                        <Lock size={12} /> Area Psicologo
                    </a>
                 </div>
                 <button
                    onClick={handleSubmit}
                    disabled={isSubmitting}
                    className="w-full md:w-auto bg-green-600 text-white px-8 py-3 rounded-lg font-bold shadow-md hover:bg-green-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                 >
                    {isSubmitting ? 'Invio in corso...' : (
                        <>
                            <Send size={18} /> Invia Assessment
                        </>
                    )}
                 </button>
            </div>
        </main>
    </div>
  );
};

