import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, Cell 
} from 'recharts';
import { Download } from 'lucide-react';
import { AthleteProfile, QuestionnaireData } from '../types';
import { IPPS_SUBSCALES, CT_SUBSCALES, PESD_CATEGORIES } from '../constants';

interface ResultsTabProps {
    profile: AthleteProfile;
    data: QuestionnaireData;
}

// Flux Colors
const COLORS = {
    positive: '#38bdf8', // Sky 400
    negative: '#f87171', // Red 400
    challenge: '#4ade80', // Green 400
    pesd: '#c084fc',     // Purple 400
    text: '#e2e8f0',     // Slate 200
    grid: '#334155'      // Slate 700
};

const mean = (indices: number[], values: number[]) => {
    if (indices.length === 0) return 0;
    const sum = indices.reduce((acc, idx) => acc + (values[idx] || 0), 0);
    return sum / indices.length;
};

export const ResultsTab: React.FC<ResultsTabProps> = ({ profile, data }) => {

    const results = useMemo(() => {
        // IPPS Calculation
        const ippsScores = [
            { name: '▲ Fiducia', val: mean(IPPS_SUBSCALES.confidence, data.ipps), fill: COLORS.positive },
            { name: '▲ Ctrl Arousal', val: mean(IPPS_SUBSCALES.control, data.ipps), fill: COLORS.positive },
            { name: '▼ Preoccupazione', val: mean(IPPS_SUBSCALES.worry, data.ipps), fill: COLORS.negative },
            { name: '▼ Dist. Conc.', val: mean(IPPS_SUBSCALES.distraction, data.ipps), fill: COLORS.negative },
        ];

        // MTS Calculation
        const mtsScore = data.mts.reduce((a, b) => a + b, 0) / data.mts.length;

        // CT Calculation
        const ctScores = [
            { name: 'Challenge', val: mean(CT_SUBSCALES.challenge, data.ct), fill: COLORS.challenge },
            { name: 'Threat', val: mean(CT_SUBSCALES.threat, data.ct), fill: COLORS.negative },
        ];

        // PESD Calculation
        const pesdScores = PESD_CATEGORIES.map((cat, i) => {
            const indices = [i, i + 10, i + 20];
            const val = mean(indices, data.pesd);
            return { name: cat, val: val, fill: COLORS.pesd };
        });

        // PESD Total
        const pesdTotal = pesdScores.reduce((acc, curr) => acc + curr.val, 0) / pesdScores.length;
        pesdScores.push({ name: 'PESD Totale', val: pesdTotal, fill: '#d8b4fe' }); // Lighter purple

        return { ippsScores, mtsScore, ctScores, pesdScores };
    }, [data]);

    const downloadCSV = () => {
        const headers = [
            "Atleta", "Disciplina", "Data", "Email", "Telefono",
            "IPPS Fiducia", "IPPS Controllo", "IPPS Preoccupazione", "IPPS Distrazione",
            "MTS Total",
            "CT Challenge", "CT Threat",
            ...PESD_CATEGORIES, "PESD Totale"
        ];

        const row = [
            profile.name, profile.discipline, new Date().toLocaleDateString(), profile.email, profile.phone,
            results.ippsScores[0].val.toFixed(2), results.ippsScores[1].val.toFixed(2), results.ippsScores[2].val.toFixed(2), results.ippsScores[3].val.toFixed(2),
            results.mtsScore.toFixed(2),
            results.ctScores[0].val.toFixed(2), results.ctScores[1].val.toFixed(2),
            ...results.pesdScores.map(s => s.val.toFixed(2))
        ];

        const csvContent = "data:text/csv;charset=utf-8," + [headers.join(","), row.join(",")].join("\n");
        const encodedUri = encodeURI(csvContent);
        const link = document.createElement("a");
        link.setAttribute("href", encodedUri);
        link.setAttribute("download", `flux_assessment_${profile.name.replace(/\s+/g, '_')}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const CustomTooltip = ({ active, payload }: any) => {
        if (active && payload && payload.length) {
            return (
                <div className="bg-slate-800 p-3 border border-slate-700 shadow-2xl rounded text-sm text-white">
                    <p className="font-bold text-slate-200 mb-1">{payload[0].payload.name}</p>
                    <p className="font-mono text-cyan-400 font-bold text-lg">{Number(payload[0].value).toFixed(2)}</p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="space-y-10 pb-20">
            <div className="bg-slate-900 p-6 rounded-xl shadow-lg border-l-4 border-red-500 flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-black text-white tracking-tight">Analisi Profilo</h2>
                    <div className="flex flex-col gap-1 mt-2 text-sm text-slate-400">
                        <span>Atleta: <strong className="text-slate-200">{profile.name}</strong></span>
                        <span>Disciplina: {profile.discipline}</span>
                        <span>{profile.email} | {profile.phone}</span>
                    </div>
                </div>
                <button onClick={downloadCSV} className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-lg transition-colors font-medium border border-slate-700">
                    <Download size={18} /> <span className="hidden sm:inline">Scarica CSV</span>
                </button>
            </div>

            {/* Score Cards Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <div className="bg-slate-900 p-5 rounded-lg border border-slate-800 hover:border-blue-500/50 transition-all">
                    <h4 className="font-bold text-blue-400 mb-4 border-b border-slate-800 pb-2">IPPS-24</h4>
                    <div className="space-y-2 text-sm text-slate-300">
                        {results.ippsScores.map(s => (
                            <div key={s.name} className="flex justify-between">
                                <span>{s.name}</span>
                                <span className="font-bold text-white">{s.val.toFixed(2)}</span>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="bg-slate-900 p-5 rounded-lg border border-slate-800 hover:border-purple-500/50 transition-all">
                    <h4 className="font-bold text-purple-400 mb-4 border-b border-slate-800 pb-2">MTS</h4>
                    <div className="flex justify-between items-center h-full pb-4">
                        <span className="text-sm text-slate-300">Mental Toughness</span>
                        <span className="text-3xl font-bold text-purple-400">{results.mtsScore.toFixed(2)}</span>
                    </div>
                </div>

                <div className="bg-slate-900 p-5 rounded-lg border border-slate-800 hover:border-green-500/50 transition-all">
                    <h4 className="font-bold text-green-400 mb-4 border-b border-slate-800 pb-2">C&T</h4>
                    <div className="space-y-2 text-sm text-slate-300">
                        {results.ctScores.map(s => (
                            <div key={s.name} className="flex justify-between">
                                <span>{s.name}</span>
                                <span className="font-bold text-white">{s.val.toFixed(2)}</span>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="bg-slate-900 p-5 rounded-lg border border-slate-800 hover:border-slate-500/50 transition-all">
                     <h4 className="font-bold text-slate-300 mb-4 border-b border-slate-800 pb-2">PESD Index</h4>
                     <div className="flex justify-between items-center h-full pb-4">
                        <span className="text-sm text-slate-400">Totale</span>
                        <span className="text-3xl font-bold text-white">{results.pesdScores[10].val.toFixed(2)}</span>
                    </div>
                </div>
            </div>

            {/* Grafici Orizzontali */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

                {/* IPPS Chart */}
                <div className="bg-slate-900 p-6 rounded-xl shadow-lg border border-slate-800">
                    <h3 className="text-lg font-bold text-slate-200 mb-4">Profilo IPPS-24</h3>
                    <div className="h-[300px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart layout="vertical" data={results.ippsScores} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke={COLORS.grid} />
                                <XAxis type="number" domain={[0, 6]} tickCount={7} stroke={COLORS.text} tick={{fontSize: 10}} />
                                <YAxis dataKey="name" type="category" width={110} tick={{fontSize: 11, fontWeight: 600, fill: COLORS.text}} stroke={COLORS.text} />
                                <Tooltip content={<CustomTooltip />} cursor={{fill: 'rgba(255,255,255,0.05)'}} />
                                <Bar dataKey="val" radius={[0, 4, 4, 0]} barSize={25} label={{ position: 'right', fill: '#94a3b8', fontSize: 11, formatter: (v: number) => v.toFixed(2) }}>
                                    {results.ippsScores.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={entry.fill} />
                                    ))}
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* CT Chart */}
                <div className="bg-slate-900 p-6 rounded-xl shadow-lg border border-slate-800">
                    <h3 className="text-lg font-bold text-slate-200 mb-4">Profilo Challenge & Threat</h3>
                    <div className="h-[300px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart layout="vertical" data={results.ctScores} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke={COLORS.grid} />
                                <XAxis type="number" domain={[0, 7]} tickCount={8} stroke={COLORS.text} tick={{fontSize: 10}} />
                                <YAxis dataKey="name" type="category" width={80} tick={{fontSize: 12, fontWeight: 600, fill: COLORS.text}} stroke={COLORS.text} />
                                <Tooltip content={<CustomTooltip />} cursor={{fill: 'rgba(255,255,255,0.05)'}} />
                                <Bar dataKey="val" radius={[0, 4, 4, 0]} barSize={40} label={{ position: 'right', fill: '#94a3b8', fontSize: 11, formatter: (v: number) => v.toFixed(2) }}>
                                    {results.ctScores.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={entry.fill} />
                                    ))}
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>

