                                <button onClick={() => setActiveTab(3)} className={`py-4 border-b-2 transition-colors ${activeTab === 3 ? 'border-cyan-500 text-cyan-400' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>PESD</button>
