                                <div className={activeTab === 2 ? 'block pointer-events-none opacity-80' : 'hidden'}><CtTab data={ctData} onChange={()=>{}} /></div>
                                <div className={activeTab === 3 ? 'block pointer-events-none opacity-80' : 'hidden'}><PesdTab data={pesdData} onChange={()=>{}} /></div>
