import React, { useState } from 'react';
import { Target, Brain, Swords, Activity, Send, CheckCircle, AlertCircle, Lock, Info } from 'lucide-react';
import { Sidebar } from '../components/Sidebar';
import { IppsTab, MtsTab, CtTab } from '../components/Questionnaires';
import { PesdTab } from '../components/PesdTab';
import { IPPS_ITEMS, MTS_ITEMS, CT_ITEMS, PESD_ITEMS } from '../constants';
import { AthleteProfile } from '../types';
import { supabase } from '../lib/supabase';

export const AthletePage = () => {
  const [profile, setProfile] = useState<AthleteProfile>({
    name: '',
    discipline: 'Carabina',
    yearsOfPractice: 0,
    email: '',
    phone: ''
  });

  const [ippsData, setIppsData] = useState<number[]>(new Array(IPPS_ITEMS.length).fill(3));
  const [mtsData, setMtsData] = useState<number[]>(new Array(MTS_ITEMS.length).fill(3));
  const [ctData, setCtData] = useState<number[]>(new Array(CT_ITEMS.length).fill(4));
  const [pesdData, setPesdData] = useState<number[]>(new Array(PESD_ITEMS.length).fill(0));

  const [activeTab, setActiveTab] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleProfileChange = (field: keyof AthleteProfile, value: string | number) => {
    setProfile(prev => ({ ...prev, [field]: value }));
    if (errorMsg) setErrorMsg(null);
  };

  const updateQuestionnaire = (setter: React.Dispatch<React.SetStateAction<number[]>>, index: number, val: number) => {
    setter(prev => {
      const copy = [...prev];
      copy[index] = val;
      return copy;
    });
  };

  const validate = () => {
    if (!profile.name.trim()) return "Il campo 'Nome e Cognome' è obbligatorio.";
    if (!profile.email.trim() && !profile.phone.trim()) return "È necessario inserire almeno un contatto (Email o Telefono).";
    return null;
  };

  const handleSubmit = async () => {
    const errorValidation = validate();
    if (errorValidation) {
      setErrorMsg(errorValidation);
      window.scrollTo(0, 0);
      return;
    }

    setIsSubmitting(true);
    setErrorMsg(null);

    try {
      const { error } = await supabase.from('assessments').insert({
        athlete_name: profile.name,
        discipline: profile.discipline,
        years_of_practice: profile.yearsOfPractice,
        email: profile.email,
        phone: profile.phone,
        ipps: ippsData,
        mts: mtsData,
        ct: ctData,
        pesd: pesdData
      });

      if (error) {
          console.error("Supabase Error:", error);
          if (error.code === '42P01') {
              setErrorMsg("⚠️ CONFIGURAZIONE DATABASE MANCANTE: La tabella 'assessments' non esiste.");
          } else {
              setErrorMsg("Errore durante il salvataggio: " + error.message);
          }
          return;
      }

      setSubmitted(true);
    } catch (err) {
      console.error("Unexpected Error:", err);
      setErrorMsg("Errore imprevisto di connessione.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-slate-900 border border-slate-800 max-w-md w-full p-8 rounded-2xl shadow-2xl text-center">
            <div className="flex justify-center mb-6">
                <CheckCircle className="w-20 h-20 text-green-400 shadow-[0_0_20px_rgba(74,222,128,0.3)] rounded-full" />
            </div>
            <h1 className="text-3xl font-bold text-white mb-2">Grazie {profile.name}!</h1>
            <p className="text-slate-400 mb-8">
                I tuoi dati sono stati inviati correttamente al Dr. Massimiliano Di Liborio.
            </p>
            <div className="flex flex-col gap-4">
                <button 
                    onClick={() => window.location.reload()} 
                    className="text-sm text-slate-500 hover:text-slate-300 underline transition-colors"
                >
                    Compila un altro questionario
                </button>
                <a href="#/dashboard" className="inline-flex items-center justify-center gap-2 px-4 py-3 bg-slate-800 text-slate-200 rounded-lg hover:bg-slate-700 font-bold transition-all border border-slate-700">
                    <Lock size={16} /> Vai alla Dashboard
                </a>
            </div>
        </div>
      </div>
    );
  }

  const tabs = [
    { id: 0, label: 'IPPS-24', icon: Target, component: <IppsTab data={ippsData} onChange={(i, v) => updateQuestionnaire(setIppsData, i, v)} /> },
    { id: 1, label: 'MTS', icon: Brain, component: <MtsTab data={mtsData} onChange={(i, v) => updateQuestionnaire(setMtsData, i, v)} /> },
    { id: 2, label: 'C&T', icon: Swords, component: <CtTab data={ctData} onChange={(i, v) => updateQuestionnaire(setCtData, i, v)} /> },
    { id: 3, label: 'PESD', icon: Activity, component: <PesdTab data={pesdData} onChange={(i, v) => updateQuestionnaire(setPesdData, i, v)} /> }
  ];

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-slate-950 font-sans text-slate-200">
        {/* Sidebar always visible on desktop */}
        <div className="hidden md:block">
            <Sidebar profile={profile} onChange={handleProfileChange} />
        </div>

        {/* Mobile Header */}
        <div className="md:hidden bg-slate-900 border-b border-slate-800 p-4 sticky top-0 z-20 shadow-lg">
             <div className="flex items-center gap-2 font-black text-white mb-4">
                <span className="bg-yellow-400 p-1 rounded text-slate-900"><Target size={16} fill="currentColor" /></span>
                FLUX Assessment
            </div>
            <div className="space-y-2">
                <input 
                    type="text" 
                    placeholder="Nome e Cognome *" 
                    className="w-full p-3 bg-slate-950 border border-slate-700 rounded-lg text-white focus:border-cyan-500 outline-none"
                    value={profile.name}
                    onChange={(e) => handleProfileChange('name', e.target.value)}
                />
            </div>
        </div>

        <main className="flex-1 flex flex-col h-full overflow-hidden w-full relative">

            {/* Validation Banner */}
            {errorMsg && (
                <div className="bg-red-500/10 border-b border-red-500/20 text-red-400 px-6 py-3 flex items-center gap-3 backdrop-blur-sm">
                    <AlertCircle size={20} />
                    <span className="font-bold">{errorMsg}</span>
                </div>
            )}

            {/* General Instructions Banner */}
            <div className="bg-yellow-500/5 border-b border-yellow-500/10 p-4 flex gap-3 items-start backdrop-blur-md">
                <div className="bg-yellow-500/10 p-2 rounded-full text-yellow-500 mt-0.5 shrink-0">
                    <Info size={20} />
                </div>
                <div className="text-sm text-slate-300">
                    <p className="font-bold text-yellow-500 mb-1">Istruzioni importanti:</p>
                    <p className="leading-relaxed">
                        Qui in basso sono presenti <strong className="text-white">4 questionari differenti</strong> (scorri le schede). 
                        Compilali tutti e 4. Poi premi il tasto verde <strong className="text-green-400">"Invia Assessment"</strong> in basso a destra.
                    </p>
                </div>
            </div>

            <div className="bg-slate-900 border-b border-slate-800 px-6 overflow-x-auto scrollbar-hide flex-shrink-0 shadow-lg">
                <div className="flex space-x-8 min-w-max">
                    {tabs.map((tab) => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`flex items-center gap-2 py-5 px-1 border-b-2 transition-all font-bold text-sm tracking-wide
                        ${activeTab === tab.id 
                            ? 'border-cyan-500 text-cyan-400 drop-shadow-[0_0_10px_rgba(6,182,212,0.5)]' 
                            : 'border-transparent text-slate-500 hover:text-slate-300'}`}
                    >
                        <tab.icon size={18} />
                        {tab.label}
                    </button>
                    ))}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8 pb-32 bg-slate-950 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
                <div className="max-w-4xl mx-auto">
                    {tabs[activeTab].component}
                </div>
            </div>

            {/* Bottom Floating Submit Bar */}
            <div className="absolute bottom-0 left-0 w-full bg-slate-900/90 backdrop-blur-lg border-t border-slate-800 p-4 shadow-[0_-5px_20px_rgba(0,0,0,0.5)] z-10 flex justify-between items-center">
                 <div className="flex flex-col">
                    <div className="text-xs text-slate-500 hidden md:block font-medium">
                        Completa tutte le sezioni prima di inviare.
                    </div>
                    {/* Link "nascosto" per accesso rapido in preview */}
                    <a href="#/dashboard" className="text-xs text-slate-700 hover:text-cyan-500 flex items-center gap-1 mt-1 font-medium transition-colors cursor-pointer">
                        <Lock size={12} /> Area Psicologo
                    </a>
                 </div>
                 <button
                    onClick={handleSubmit}
                    disabled={isSubmitting}
                    className="w-full md:w-auto bg-gradient-to-r from-green-600 to-green-500 text-slate-950 px-8 py-3 rounded-lg font-black shadow-[0_0_20px_rgba(34,197,94,0.3)] hover:shadow-[0_0_30px_rgba(34,197,94,0.5)] hover:from-green-500 hover:to-green-400 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed disabled:shadow-none"
                 >
                    {isSubmitting ? 'Invio in corso...' : (
                        <>
                            <Send size={18} strokeWidth={3} /> INVIA ASSESSMENT
                        </>
                    )}
                 </button>
            </div>
        </main>
    </div>
  );
};

