        discipline: profile.discipline,
        years_of_practice: profile.yearsOfPractice,
        email: profile.email,
        phone: profile.phone,
        ipps: ippsData,
        mts: mtsData,
        ct: ctData,
        pesd: pesdData
      });

      if (error) {
          console.error("Supabase Error:", error);
          if (error.code === '42P01') {
              setErrorMsg("⚠️ CONFIGURAZIONE DATABASE MANCANTE: La tabella 'assessments' non esiste.");
          } else {
              setErrorMsg("Errore durante il salvataggio: " + error.message);
          }
          return;
      }

      setSubmitted(true);
    } catch (err) {
      console.error("Unexpected Error:", err);
      setErrorMsg("Errore imprevisto di connessione.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-slate-900 border border-slate-800 max-w-md w-full p-8 rounded-2xl shadow-2xl text-center">
            <div className="flex justify-center mb-6">
                <CheckCircle className="w-20 h-20 text-green-400 shadow-[0_0_20px_rgba(74,222,128,0.3)] rounded-full" />
            </div>
            <h1 className="text-3xl font-bold text-white mb-2">Grazie {profile.name}!</h1>
            <p className="text-slate-400 mb-8">
                I tuoi dati sono stati inviati correttamente al Dr. Massimiliano Di Liborio.
            </p>
            <div className="flex flex-col gap-4">
                <button 
                    onClick={() => window.location.reload()} 
                    className="text-sm text-slate-500 hover:text-slate-300 underline transition-colors"
                >
                    Compila un altro questionario
                </button>
                <a href="#/dashboard" className="inline-flex items-center justify-center gap-2 px-4 py-3 bg-slate-800 text-slate-200 rounded-lg hover:bg-slate-700 font-bold transition-all border border-slate-700">
                    <Lock size={16} /> Vai alla Dashboard
                </a>
            </div>
        </div>
      </div>
    );
  }

  const tabs = [
    { id: 0, label: 'IPPS-24', icon: Target, component: <IppsTab data={ippsData} onChange={(i, v) => updateQuestionnaire(setIppsData, i, v)} /> },
    { id: 1, label: 'MTS', icon: Brain, component: <MtsTab data={mtsData} onChange={(i, v) => updateQuestionnaire(setMtsData, i, v)} /> },
    { id: 2, label: 'C&T', icon: Swords, component: <CtTab data={ctData} onChange={(i, v) => updateQuestionnaire(setCtData, i, v)} /> },
    { id: 3, label: 'PESD', icon: Activity, component: <PesdTab data={pesdData} onChange={(i, v) => updateQuestionnaire(setPesdData, i, v)} /> }
  ];

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-slate-950 font-sans text-slate-200">
        {/* Sidebar always visible on desktop */}
        <div className="hidden md:block">
            <Sidebar profile={profile} onChange={handleProfileChange} />
        </div>

        {/* Mobile Header & Profile Management */}
        <div className="md:hidden flex flex-col bg-slate-900 border-b border-slate-800 z-30 shadow-lg relative">
             <div className="flex items-center justify-between p-4">
                <div className="flex items-center gap-2 font-black text-white">
                    <span className="bg-yellow-400 p-1 rounded text-slate-900"><Target size={16} fill="currentColor" /></span>
                    FLUX Assessment
                </div>
                <button 
                    onClick={() => setIsMobileProfileOpen(!isMobileProfileOpen)}
                    className={`flex items-center gap-1 text-xs font-bold uppercase tracking-wider px-3 py-1.5 rounded-full transition-all ${isMobileProfileOpen ? 'bg-cyan-900/50 text-cyan-400' : 'bg-slate-800 text-slate-400'}`}
                >
                    <User size={14} /> Dati Atleta {isMobileProfileOpen ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                </button>
            </div>

            {/* Collapsible Mobile Profile Form */}
            {isMobileProfileOpen && (
                <div className="px-4 pb-6 space-y-4 bg-slate-900 border-b border-slate-800 animate-in slide-in-from-top-2 duration-200">
                    <div className="bg-slate-950/50 p-4 rounded-xl border border-slate-800 space-y-4">
                        <div>
                            <label className="text-xs text-slate-500 font-bold uppercase mb-1 block">Nome e Cognome *</label>
                            <input 
                                type="text" 
                                className="w-full p-2.5 bg-slate-900 border border-slate-700 rounded-lg text-white focus:border-cyan-500 outline-none"
                                value={profile.name}
                                onChange={(e) => handleProfileChange('name', e.target.value)}
                                placeholder="Es. Mario Rossi"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="text-xs text-slate-500 font-bold uppercase mb-1 block flex items-center gap-1"><Trophy size={10} /> Disciplina</label>
                                <select 
                                    className="w-full p-2.5 bg-slate-900 border border-slate-700 rounded-lg text-white focus:border-cyan-500 outline-none appearance-none"
                                    value={profile.discipline}
                                    onChange={(e) => handleProfileChange('discipline', e.target.value)}
                                >
                                    {DISCIPLINES.map(d => (
                                        <option key={d} value={d}>{d}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="text-xs text-slate-500 font-bold uppercase mb-1 block flex items-center gap-1"><Calendar size={10} /> Anni Pratica</label>
                                <input 
                                    type="number" 
                                    className="w-full p-2.5 bg-slate-900 border border-slate-700 rounded-lg text-white focus:border-cyan-500 outline-none"
                                    value={profile.yearsOfPractice}
                                    onChange={(e) => handleProfileChange('yearsOfPractice', parseInt(e.target.value) || 0)}
                                />
                            </div>
                        </div>

                        <div className="space-y-3 pt-2 border-t border-slate-800">
                            <p className="text-[10px] text-slate-400 italic">Compila almeno un contatto *</p>
                            <div>
                                <label className="text-xs text-slate-500 font-bold uppercase mb-1 block flex items-center gap-1"><Mail size={10} /> Email</label>
                                <input 
                                    type="email" 
                                    className="w-full p-2.5 bg-slate-900 border border-slate-700 rounded-lg text-white focus:border-cyan-500 outline-none placeholder-slate-600"
                                    value={profile.email}
                                    onChange={(e) => handleProfileChange('email', e.target.value)}
                                    placeholder="email@esempio.com"
                                />
                            </div>
                            <div>
                                <label className="text-xs text-slate-500 font-bold uppercase mb-1 block flex items-center gap-1"><Phone size={10} /> Telefono</label>
                                <input 
                                    type="tel" 
                                    className="w-full p-2.5 bg-slate-900 border border-slate-700 rounded-lg text-white focus:border-cyan-500 outline-none placeholder-slate-600"
                                    value={profile.phone}
                                    onChange={(e) => handleProfileChange('phone', e.target.value)}
                                    placeholder="+39 ..."
                                />
                            </div>
                        </div>

                        <button 
                            onClick={() => setIsMobileProfileOpen(false)}
                            className="w-full py-2 bg-slate-800 text-slate-300 text-xs font-bold uppercase rounded-lg hover:bg-slate-700 mt-2"
                        >
                            Chiudi e compila questionari
                        </button>
                    </div>
                </div>
            )}
        </div>

        <main className="flex-1 flex flex-col h-full overflow-hidden w-full relative">

            {/* Validation Banner */}
            {errorMsg && (
                <div className="bg-red-500/10 border-b border-red-500/20 text-red-400 px-6 py-3 flex items-center gap-3 backdrop-blur-sm animate-pulse">
                    <AlertCircle size={20} className="shrink-0" />
                    <span className="font-bold text-xs sm:text-sm">{errorMsg}</span>
                </div>
            )}

            {/* General Instructions Banner */}
            <div className="bg-yellow-500/5 border-b border-yellow-500/10 p-4 flex gap-3 items-start backdrop-blur-md">
                <div className="bg-yellow-500/10 p-2 rounded-full text-yellow-500 mt-0.5 shrink-0">
                    <Info size={16} />
                </div>
                <div className="text-xs sm:text-sm text-slate-300">
                    <p className="font-bold text-yellow-500 mb-1">Istruzioni importanti:</p>
                    <p className="leading-relaxed">
                        Qui in basso sono presenti <strong className="text-white">4 questionari differenti</strong> (scorri le schede). 
                        Compilali tutti e 4. Poi premi il tasto verde <strong className="text-green-400">"Invia Assessment"</strong> in basso.
                    </p>
                </div>
            </div>

            <div className="bg-slate-900 border-b border-slate-800 px-4 sm:px-6 overflow-x-auto scrollbar-hide flex-shrink-0 shadow-lg">
                <div className="flex space-x-6 sm:space-x-8 min-w-max">
                    {tabs.map((tab) => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`flex items-center gap-2 py-4 sm:py-5 px-1 border-b-2 transition-all font-bold text-xs sm:text-sm tracking-wide
                        ${activeTab === tab.id 
                            ? 'border-cyan-500 text-cyan-400 drop-shadow-[0_0_10px_rgba(6,182,212,0.5)]' 
                            : 'border-transparent text-slate-500 hover:text-slate-300'}`}
                    >
                        <tab.icon size={16} />
                        {tab.label}
                    </button>
                    ))}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8 pb-32 md:pb-32 bg-slate-950 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
                <div className="max-w-4xl mx-auto">
                    {tabs[activeTab].component}
                </div>
            </div>

            {/* Bottom Floating Submit Bar */}
            <div className="absolute bottom-0 left-0 w-full bg-slate-900/95 backdrop-blur-lg border-t border-slate-800 p-4 shadow-[0_-5px_30px_rgba(0,0,0,0.6)] z-40 flex justify-between items-center">
                 <div className="flex flex-col">
                    <div className="text-xs text-slate-500 hidden md:block font-medium">
                        Completa tutte le sezioni prima di inviare.
                    </div>
                    {/* Link "nascosto" per accesso rapido in preview */}
                    <a href="#/dashboard" className="text-xs text-slate-700 hover:text-cyan-500 flex items-center gap-1 mt-1 font-medium transition-colors cursor-pointer">
                        <Lock size={12} /> <span className="hidden sm:inline">Area Psicologo</span>
                    </a>
                 </div>
                 <button
                    onClick={handleSubmit}
                    disabled={isSubmitting}
                    className="w-full md:w-auto bg-gradient-to-r from-green-600 to-green-500 text-slate-950 px-6 py-3 rounded-lg font-black shadow-[0_0_20px_rgba(34,197,94,0.3)] hover:shadow-[0_0_30px_rgba(34,197,94,0.5)] hover:from-green-500 hover:to-green-400 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed disabled:shadow-none active:scale-95"
                 >
                    {isSubmitting ? 'Invio...' : (
                        <>
                            <Send size={18} strokeWidth={3} /> <span className="uppercase tracking-wider">Invia Assessment</span>
                        </>
                    )}
                 </button>
            </div>
        </main>
    </div>
  );
};

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  // Configurazione server di sviluppo
  server: {
    host: '0.0.0.0',
    port: 8080
  },
  // Configurazione server di produzione (Preview/Cloud Run)
  preview: {
    host: '0.0.0.0', // Obbligatorio per Docker/Cloud Run
    port: Number(process.env.PORT) || 8080, // Usa la porta iniettata da Cloud Run o 8080
  }
});

import React, { useState } from 'react';
import { Target, Brain, Swords, Activity, Send, CheckCircle, AlertCircle, Lock, Info, ChevronDown, ChevronUp, User, Mail, Phone, Trophy, Calendar, Zap } from 'lucide-react';
import { Sidebar } from '../components/Sidebar';
import { IppsTab, MtsTab, CtTab } from '../components/Questionnaires';
import { PesdTab } from '../components/PesdTab';
import { IPPS_ITEMS, MTS_ITEMS, CT_ITEMS, PESD_ITEMS, DISCIPLINES } from '../constants';
import { AthleteProfile } from '../types';
import { supabase } from '../lib/supabase';

export const AthletePage = () => {
  const [profile, setProfile] = useState<AthleteProfile>({
    name: '',
    discipline: 'Carabina',
    yearsOfPractice: 0,
    email: '',
    phone: ''
  });

  const [ippsData, setIppsData] = useState<number[]>(new Array(IPPS_ITEMS.length).fill(3));
  const [mtsData, setMtsData] = useState<number[]>(new Array(MTS_ITEMS.length).fill(3));
  const [ctData, setCtData] = useState<number[]>(new Array(CT_ITEMS.length).fill(4));
  const [pesdData, setPesdData] = useState<number[]>(new Array(PESD_ITEMS.length).fill(0));

  const [activeTab, setActiveTab] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const [isMobileProfileOpen, setIsMobileProfileOpen] = useState(true);

  const handleProfileChange = (field: keyof AthleteProfile, value: string | number) => {
    setProfile(prev => ({ ...prev, [field]: value }));
    if (errorMsg) setErrorMsg(null);
  };

  const updateQuestionnaire = (setter: React.Dispatch<React.SetStateAction<number[]>>, index: number, val: number) => {
    setter(prev => {
      const copy = [...prev];
      copy[index] = val;
      return copy;
    });
  };

  const validate = () => {
    if (!profile.name.trim()) return "Campo 'Nome e Cognome' richiesto.";
    if (!profile.email.trim() && !profile.phone.trim()) return "Inserire contatto (Email o Telefono).";
    return null;
  };

  const handleSubmit = async () => {
    const errorValidation = validate();
    if (errorValidation) {
      setErrorMsg(errorValidation);
      if (window.innerWidth < 768) {
          setIsMobileProfileOpen(true);
          window.scrollTo(0, 0);
      }
      return;
    }

    setIsSubmitting(true);
    setErrorMsg(null);

    try {
      const { error } = await supabase.from('assessments').insert({
        athlete_name: profile.name,
        discipline: profile.discipline,
        years_of_practice: profile.yearsOfPractice,
        email: profile.email,
        phone: profile.phone,
        ipps: ippsData,
        mts: mtsData,
        ct: ctData,
        pesd: pesdData
      });

      if (error) {
          console.error("Supabase Error:", error);
          if (error.code === '42P01') {
              setErrorMsg("⚠️ DB ERROR: Tabella 'assessments' mancante.");
          } else {
              setErrorMsg("Errore salvataggio: " + error.message);
          }
          return;
      }

      setSubmitted(true);
    } catch (err) {
      console.error("Unexpected Error:", err);
      setErrorMsg("Errore connessione.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4 relative overflow-hidden">
        {/* Background Grid */}
        <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20"></div>

        <div className="glass-panel max-w-md w-full p-8 rounded border border-cyan-500/30 shadow-[0_0_50px_rgba(6,182,212,0.2)] text-center relative z-10">
            <div className="flex justify-center mb-6">
                <div className="relative">
                    <div className="absolute inset-0 bg-green-500 blur-xl opacity-30 rounded-full animate-pulse"></div>
                    <CheckCircle className="w-20 h-20 text-green-400 relative z-10" strokeWidth={1.5} />
                </div>
            </div>
            <h1 className="text-3xl font-black text-white mb-2 tracking-tight">DATA_UPLOADED</h1>
            <p className="text-cyan-400/80 mb-8 font-mono text-sm">
                Grazie {profile.name}. Assessment registrato.
            </p>
            <div className="flex flex-col gap-4">
                <button 
                    onClick={() => window.location.reload()} 
                    className="text-xs font-mono text-slate-500 hover:text-cyan-400 underline transition-colors uppercase tracking-widest"
                >
                    Nuova Sessione
                </button>
                <a href="#/dashboard" className="inline-flex items-center justify-center gap-2 px-6 py-3 bg-slate-900/80 text-cyan-400 border border-cyan-500/30 rounded hover:bg-cyan-950 hover:border-cyan-400 hover:shadow-[0_0_20px_rgba(6,182,212,0.3)] font-bold transition-all uppercase tracking-wider text-sm">
                    <Lock size={14} /> Accesso_Psy
                </a>
            </div>
        </div>
      </div>
    );
  }

  const tabs = [
    { id: 0, label: 'IPPS-24', icon: Target, component: <IppsTab data={ippsData} onChange={(i, v) => updateQuestionnaire(setIppsData, i, v)} /> },
    { id: 1, label: 'MTS', icon: Brain, component: <MtsTab data={mtsData} onChange={(i, v) => updateQuestionnaire(setMtsData, i, v)} /> },
    { id: 2, label: 'C&T', icon: Swords, component: <CtTab data={ctData} onChange={(i, v) => updateQuestionnaire(setCtData, i, v)} /> },
    { id: 3, label: 'PESD', icon: Activity, component: <PesdTab data={pesdData} onChange={(i, v) => updateQuestionnaire(setPesdData, i, v)} /> }
  ];

  const mobileInputClass = "w-full p-2.5 bg-slate-950/80 border border-slate-700/50 rounded text-white focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500/30 outline-none font-mono text-sm";
  const mobileLabelClass = "text-[10px] text-cyan-500 font-bold uppercase mb-1 block flex items-center gap-1 font-mono tracking-wider";

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden text-slate-200">
        <div className="hidden md:block">
            <Sidebar profile={profile} onChange={handleProfileChange} />
        </div>

        {/* Mobile Header HUD */}
        <div className="md:hidden flex flex-col bg-slate-900/90 backdrop-blur-md border-b border-cyan-900/30 z-30 relative">
             <div className="flex items-center justify-between p-4">
                <div className="flex items-center gap-2 font-black text-white tracking-tighter italic">
                    <span className="text-cyan-400"><Zap size={18} fill="currentColor" /></span>
                    FLUX<span className="text-cyan-500 text-xs self-end mb-1">.OS</span>
                </div>
                <button 
                    onClick={() => setIsMobileProfileOpen(!isMobileProfileOpen)}
                    className={`flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest px-4 py-1.5 rounded-sm transition-all border ${isMobileProfileOpen ? 'bg-cyan-950/50 border-cyan-500/50 text-cyan-400 shadow-[0_0_10px_rgba(6,182,212,0.2)]' : 'bg-slate-800 border-transparent text-slate-400'}`}
                >
                    <User size={12} /> PROFILE {isMobileProfileOpen ? <ChevronUp size={12} /> : <ChevronDown size={12} />}
                </button>
            </div>

            {isMobileProfileOpen && (
                <div className="px-4 pb-6 space-y-4 bg-slate-900/95 border-b border-cyan-500/20 shadow-2xl relative animate-in slide-in-from-top-2">
                    <div className="bg-slate-950/50 p-4 rounded border border-slate-800 space-y-4">
                        <div>
                            <label className={mobileLabelClass}>Nome Atleta *</label>
                            <input 
                                type="text" 
                                className={mobileInputClass}
                                value={profile.name}
                                onChange={(e) => handleProfileChange('name', e.target.value)}
                                placeholder="Nome e Cognome"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className={mobileLabelClass}><Trophy size={10} /> Disciplina</label>
                                <select 
                                    className={mobileInputClass}
                                    value={profile.discipline}
                                    onChange={(e) => handleProfileChange('discipline', e.target.value)}
                                >
                                    {DISCIPLINES.map(d => (
                                        <option key={d} value={d}>{d}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className={mobileLabelClass}><Calendar size={10} /> Anni Exp.</label>
                                <input 
                                    type="number" 
                                    className={mobileInputClass}
                                    value={profile.yearsOfPractice}
                                    onChange={(e) => handleProfileChange('yearsOfPractice', parseInt(e.target.value) || 0)}
                                />
                            </div>
                        </div>

                        <div className="space-y-3 pt-2 border-t border-slate-800/50">
                            <p className="text-[9px] text-slate-500 font-mono">* Richiesto almeno un contatto</p>
                            <div>
                                <label className={mobileLabelClass}><Mail size={10} /> Email</label>
                                <input 
                                    type="email" 
                                    className={mobileInputClass}
                                    value={profile.email}
                                    onChange={(e) => handleProfileChange('email', e.target.value)}
                                    placeholder="email@..."
                                />
                            </div>
                            <div>
                                <label className={mobileLabelClass}><Phone size={10} /> Telefono</label>
                                <input 
                                    type="tel" 
                                    className={mobileInputClass}
                                    value={profile.phone}
                                    onChange={(e) => handleProfileChange('phone', e.target.value)}
                                    placeholder="+39 ..."
                                />
                            </div>
                        </div>

                        <button 
                            onClick={() => setIsMobileProfileOpen(false)}
                            className="w-full py-2.5 bg-cyan-900/20 text-cyan-400 border border-cyan-500/30 text-[10px] font-bold uppercase tracking-widest rounded hover:bg-cyan-900/40 transition-all font-mono"
                        >
                            [ Chiudi Pannello ]
                        </button>
                    </div>
                </div>
            )}
        </div>

        <main className="flex-1 flex flex-col h-full overflow-hidden w-full relative">

            {errorMsg && (
                <div className="bg-red-500/10 border-b border-red-500/30 text-red-400 px-6 py-3 flex items-center gap-3 backdrop-blur-sm animate-pulse">
                    <AlertCircle size={20} className="shrink-0" />
                    <span className="font-bold text-xs sm:text-sm font-mono tracking-wide">SYSTEM ERROR: {errorMsg}</span>
                </div>
            )}

            <div className="bg-yellow-500/5 border-b border-yellow-500/10 p-3 flex gap-3 items-start backdrop-blur-md">
                <div className="text-yellow-500 mt-0.5 shrink-0 animate-pulse">
                    <Info size={16} />
                </div>
                <div className="text-[11px] sm:text-xs text-slate-400 font-mono">
                    <span className="text-yellow-500 font-bold mr-2">>> PROTOCOLLO:</span>
                    Compilare i 4 moduli sequenziali. Confermare con pulsante "INVIA" al termine.
                </div>
            </div>

            <div className="bg-slate-900/50 border-b border-white/5 px-2 sm:px-6 overflow-x-auto scrollbar-hide flex-shrink-0 backdrop-blur-sm">
                <div className="flex space-x-2 sm:space-x-4 min-w-max p-2">
                    {tabs.map((tab) => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`flex items-center gap-2 py-2 px-4 border transition-all font-bold text-[10px] sm:text-xs uppercase tracking-widest rounded-sm font-mono
                        ${activeTab === tab.id 
                            ? 'bg-cyan-950/40 border-cyan-500/50 text-cyan-400 shadow-[0_0_15px_rgba(6,182,212,0.15)]' 
                            : 'bg-transparent border-transparent text-slate-500 hover:text-slate-300 hover:bg-white/5'}`}
                    >
                        <tab.icon size={14} className={activeTab === tab.id ? 'text-cyan-400' : 'opacity-50'} />
                        {tab.label}
                    </button>
                    ))}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8 pb-32 md:pb-32 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
                <div className="max-w-5xl mx-auto">
                    {tabs[activeTab].component}
                </div>
            </div>

            {/* Cyberpunk Footer Action Bar */}
