interface SliderItemProps {
    label: string;
    value: number;
    min: number;
    max: number;
    labels: string[];
    onChange: (val: number) => void;
    colorClass: string;
}

const SliderItem: React.FC<SliderItemProps> = ({ label, value, min, max, labels, onChange, colorClass }) => {
    return (
        <div className="mb-8 p-6 bg-slate-900 rounded-xl border border-slate-800">
            <div className="flex justify-between items-start gap-4 mb-6">
                 <h4 className="text-base font-medium text-slate-200 leading-relaxed">{label}</h4>
                 <div className={`px-3 py-1 bg-slate-950 rounded-lg text-sm font-bold ${colorClass} shadow-inner min-w-[3rem] text-center`}>
                    {value}
                 </div>
            </div>

            <div className="relative mb-6 px-2">
                <input
                    type="range"
                    min={min}
                    max={max}
                    value={value}
                    onChange={(e) => onChange(parseInt(e.target.value))}
                    className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-current"
                />
                <div className="flex justify-between mt-2 text-[10px] sm:text-xs text-slate-500 font-medium uppercase tracking-wide">
                    {labels.map((l, i) => (
                        <span 
                            key={i} 
                            className={`cursor-pointer hover:text-slate-300 transition-colors ${value === min + i ? colorClass : ''}`}
                            onClick={() => onChange(min + i)}
                        >
                            {l}
                        </span>
                    ))}
                </div>
            </div>
        </div>
    );
};

